INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-07', E'남유다의 죄 (예레미야 17장)', E'예레미야 17장', E'유다의 죄는 금강석 끝 철필로 그들의 마음 판에 새겨져 있었습니다. 이는 단순히 표면적인 잘못이 아니라, 그들의 존재 깊숙이 뿌리박힌 죄성을 보여줍니다. 높은 언덕의 푸른 나무 곁에 세운 제단들과 아세라 상들은 하나님께 드려야 할 예배가 얼마나 심각하게 왜곡되었는지를 드러냅니다. 이처럼 깊이 새겨진 죄로 인해 하나님께서는 그들의 재산과 보물, 그리고 약속의 기업까지도 원수의 손에 넘기실 것을 선포하십니다.\n\n이어서 하나님은 두 가지 상반된 길을 선명하게 대조하십니다. 사람을 의지하며 육신의 힘을 믿는 자는 사막의 떨기나무와 같아서, 좋은 일이 와도 알아보지 못하고 메마른 광야에서 고독하게 살아갑니다. 반면 여호와를 의지하고 의뢰하는 자는 물가에 심긴 나무처럼 뿌리를 깊이 내려 가뭄이 와도 잎이 청청하고 열매가 그치지 않습니다. 이 비유는 단순한 축복과 저주의 대비가 아니라, 삶의 근원을 어디에 두느냐에 따른 필연적 결과를 보여줍니다.\n\n"만물보다 거짓되고 심히 부패한 것은 마음이라"(렘 17:9)는 선언은 인간 본성에 대한 하나님의 진단입니다. 그러나 절망으로 끝나지 않습니다. 심장을 살피시고 폐부를 시험하시는 하나님께서는 생수의 근원이 되어 주십니다. 예레미야가 "나를 고치소서 그리하시면 내가 낫겠나이다"라고 고백하듯, 치유와 구원의 능력은 오직 여호와께만 있습니다.\n\n마지막으로 하나님은 안식일 준수라는 구체적인 순종의 영역을 제시하십니다. 안식일에 짐을 지고 성문을 드나드는 일상의 모습은 하나님의 거룩함보다 경제적 이익을 우선시하는 그들의 가치관을 보여줍니다. 안식일을 거룩히 지키는 것은 단순한 율법 준수가 아니라, 창조주 하나님의 주권을 인정하고 그분께 삶의 우선순위를 드리는 신앙고백이었습니다. 순종하면 다윗 왕조와 예루살렘 성의 영속을, 불순종하면 꺼지지 않는 심판의 불을 예고하시는 하나님의 말씀은 오늘 우리에게도 동일한 선택을 요구합니다.', E'오늘의 핵심\n금강석 철필로 새겨진 것처럼 깊이 뿌리박힌 죄성에도 불구하고, 하나님은 여전히 생수의 근원이 되어 주시며 회개와 순종의 길을 열어두십니다.\n\n묵상 질문\n1. 내 마음 판에 하나님보다 더 깊이 새겨진 것은 무엇이며, 그것을 어떻게 하나님께 내어드릴 수 있을까요?\n2. 사막의 떨기나무처럼 사람과 세상의 힘을 의지하며 살고 있지는 않습니까? 물가의 나무처럼 하나님께 뿌리내리려면 어떤 변화가 필요할까요?\n3. 오늘날 내 삶에서 안식일의 정신을 실천한다는 것은 구체적으로 어떤 모습일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-08', E'남유다의 죄 (예레미야 18장)', E'예레미야 18장', E'하나님께서 예레미야를 토기장이의 집으로 보내십니다. 녹로(물레) 위에서 토기장이가 진흙으로 그릇을 빚다가 마음에 들지 않자 다시 뭉개어 새로운 그릇을 만드는 모습은, 이스라엘을 향한 하나님의 주권적 통치를 생생하게 보여주는 비유였습니다. "진흙이 토기장이의 손에 있음 같이 너희가 내 손에 있느니라"(렘 18:6)는 선포는 창조주이신 하나님께서 피조물인 인간과 민족의 운명을 주관하시는 절대 주권자이심을 분명히 드러냅니다.\n\n토기장이의 비유가 전하는 놀라운 소식은 하나님의 심판이 조건적이라는 사실입니다. 하나님은 어느 민족을 멸하려 하셨다가도 그들이 악에서 돌이키면 재앙의 뜻을 돌이키시고, 반대로 건설하고 심으려 하셨다가도 그들이 악을 행하면 복의 뜻을 돌이키신다고 말씀하십니다. 이는 하나님의 변덕이 아니라 인간의 자유의지와 책임을 존중하시는 하나님의 은혜로운 성품을 보여줍니다. 심판의 선포 속에서도 회개의 문은 여전히 열려 있었던 것입니다.\n\n그러나 유다 백성의 반응은 충격적이었습니다. "이는 헛되니 우리는 우리의 계획대로 행하며 우리는 각기 악한 마음이 완악한 대로 행하리라"(렘 18:12). 토기장이의 손에서 부드럽게 빚어질 수 있는 진흙이 되기를 거부하고, 스스로 굳어진 돌이 되기를 선택한 것입니다. 레바논의 만년설이 녹지 않고 산에서 흘러내리는 찬물이 마르지 않는 것처럼, 당연한 자연의 이치를 거스르는 이상한 일이 벌어진 것입니다.\n\n이런 백성의 완악함은 예레미야를 향한 적대감으로 이어집니다. 그들은 제사장의 율법과 지혜자의 책략과 선지자의 말씀이 끊어지지 않을 것이라며, 예레미야의 경고를 무시하고 오히려 그를 해하려는 음모를 꾸밉니다. 자신들의 종교 체제가 견고하다고 믿었지만, 정작 하나님의 살아있는 말씀을 거부하는 모순에 빠진 것입니다.\n\n토기장이이신 하나님은 오늘도 우리를 그분의 손에서 빚으시길 원하십니다. 때로는 우리의 계획이 무너지고 다시 시작해야 할 때가 있습니다. 그것은 실패가 아니라 더 나은 그릇으로 빚어지는 은혜의 과정입니다. 중요한 것은 ''우리의 계획대로'' 고집하며 굳어진 진흙이 되지 않는 것입니다.', E'오늘의 핵심\n토기장이이신 하나님은 회개하고 돌이키는 자를 새롭게 빚으시지만, 완악하게 자기 뜻을 고집하는 자는 심판하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 손길로 다시 빚어져야 할 부분은 무엇입니까?\n2. ''우리의 계획대로 행하리라''는 유다의 완악함이 내 안에도 있지는 않습니까?\n3. 토기장이이신 하나님의 주권을 온전히 신뢰하며 순종할 준비가 되어 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-10', E'남유다의 죄 (예레미야 19장)', E'예레미야 19장', E'토기장이의 집에서 돌아온 예레미야에게 하나님은 더 충격적인 상징 행동을 명령하십니다. 옹기를 사서 백성의 지도자들과 함께 힌놈의 아들 골짜기로 가라는 것이었습니다. 이곳은 예루살렘 남쪽에 위치한 계곡으로, 훗날 ''게헨나''라 불리며 지옥의 상징이 되는 곳입니다. 그곳에서 이루어진 가장 끔찍한 일은 자녀를 불태워 바알에게 바치는 인신제사였습니다. 하나님은 이런 장소에서 심판의 메시지를 선포하게 하신 것입니다.\n\n예레미야가 들고 간 옹기는 이미 구워져서 완성된 토기였습니다. 18장에서 토기장이가 진흙을 다시 빚는 모습이 회개의 기회를 보여주었다면, 19장의 깨진 옹기는 돌이킬 수 없는 심판을 의미합니다. "사람이 토기장이의 그릇을 한 번 깨뜨리면 다시 완전하게 할 수 없나니"(19:11)라는 선언은 유다의 운명이 봉인되었음을 보여줍니다. 백성들이 무죄한 자녀들의 피로 이 땅을 더럽혔듯이, 이제 그들 자신이 이곳에서 멸망당할 것이라는 엄중한 경고였습니다.\n\n더욱 충격적인 것은 심판의 내용입니다. 포위된 성읍 안에서 극심한 기근으로 인해 부모가 자녀를 잡아먹는 비극이 일어날 것이라는 예언은 신명기의 저주가 그대로 실현되는 것을 보여줍니다. 바알에게 자녀를 바쳤던 그들이 이제는 생존을 위해 자녀를 먹게 되는 아이러니한 심판이었습니다. \n\n이 무거운 메시지를 전한 예레미야는 성전 뜰로 돌아와 모든 백성에게 재앙을 선포합니다. 그들이 목을 곧게 하여 하나님의 말씀을 듣지 않았기 때문이라는 것입니다. 완고함이 깨진 옹기처럼 회복 불가능한 파멸로 이어진다는 엄중한 경고였습니다.\n\n오늘 우리도 깨지기 전의 옹기처럼 아직 기회가 있을 때, 목을 곧게 하지 말고 하나님의 음성에 귀 기울여야 합니다. 내 계획과 고집을 내려놓고 토기장이 되신 하나님의 손에 나를 맡길 때, 깨어짐이 아닌 새로운 빚음을 경험할 수 있을 것입니다.', E'오늘의 핵심\n하나님은 깨진 옹기를 통해 완고한 백성에게 임할 돌이킬 수 없는 심판을 선포하시며, 목을 곧게 하여 말씀을 거부하는 자의 최후를 경고하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 말씀에 목을 곧게 하고 있는 영역은 무엇입니까?\n2. 깨지기 전 옹기처럼 아직 회개의 기회가 있을 때 돌이켜야 할 죄는 무엇입니까?\n3. 토기장이 되신 하나님께 온전히 내 삶을 맡기고 있습니까, 아니면 내 계획을 고집하고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-11', E'남유다의 죄 (예레미야 20장)', E'예레미야 20장', E'예레미야의 예언 사역이 극한의 고통에 이르는 순간을 성경은 숨기지 않고 보여줍니다. 성전 총감독 바스훌은 예레미야를 때리고 나무 고랑에 채워 하룻밤 동안 베냐민 문 위층에 가두어 둡니다. 선지자가 공개적으로 모욕당하고 고문당하는 장면입니다. 다음날 풀려난 예레미야는 바스훌에게 새로운 이름을 선포합니다. "마골밋사빕" - 사방이 두려움이라는 뜻입니다. 하나님을 대적한 자가 스스로 두려움의 근원이 되고, 그 두려움 속에서 멸망할 것이라는 무서운 심판의 선언이었습니다.\n\n그런데 이어지는 예레미야의 고백은 우리를 놀라게 합니다. "여호와여 주께서 나를 권유하시므로 내가 그 권유를 받았사오며"(렘 20:7). 하나님께 붙들린 자의 솔직한 탄식이 쏟아집니다. 말씀을 전할 때마다 조롱과 모욕을 당하니 차라리 입을 다물고 싶지만, 그러면 마음속에 불이 붙는 것 같아 견딜 수 없다고 고백합니다. 하나님의 말씀이 그의 골수에 사무쳐 있기 때문입니다. 예언자는 말씀을 전하면 고통스럽고, 전하지 않으면 더 고통스러운 이중의 아픔 속에 있었습니다.\n\n예레미야의 고백은 극단으로 치닫습니다. 자신이 태어난 날을 저주하며, 차라리 태중에서 죽었더라면 좋았을 것이라고 절규합니다. 욥의 탄식을 연상시키는 이 처절한 고백은 하나님의 종이 겪는 실존적 고통의 깊이를 보여줍니다. 그러나 주목할 것은 이런 극한의 고통 속에서도 예레미야가 하나님을 떠나지 않았다는 점입니다. 오히려 "두려운 용사 같으신" 여호와가 자신과 함께하심을 고백하며, 그분의 공의로운 심판을 구합니다.\n\n오늘날 우리도 신앙 때문에 조롱받거나 불이익을 당할 때가 있습니다. 직장에서 신앙의 가치관을 지키려다 소외되거나, 믿지 않는 가족들 사이에서 외로움을 느낄 수도 있습니다. 그럴 때 예레미야의 정직한 고백이 우리에게 위로가 됩니다. 하나님께서는 우리의 솔직한 탄식과 아픔을 다 아시며, 그 고통 중에도 함께하시는 분이십니다. 말씀에 붙들린 삶이 때로는 무겁지만, 그 말씀이 우리 안에 꺼지지 않는 불이 되어 끝까지 믿음의 길을 걷게 하실 것입니다.', E'오늘의 핵심\n하나님의 말씀에 붙들린 예레미야는 극심한 고통 속에서도 그 말씀을 전하기를 멈출 수 없었고, 정직한 탄식 가운데서도 하나님을 신뢰했습니다.\n\n묵상 질문\n1. 신앙 때문에 조롱이나 어려움을 당할 때, 나는 예레미야처럼 하나님께 솔직하게 내 아픔을 고백하고 있습니까?\n2. 하나님의 말씀이 내 안에서 꺼지지 않는 불처럼 타오르는 경험을 해본 적이 있습니까?\n3. 극한의 고통 속에서도 "두려운 용사 같으신" 하나님이 나와 함께하심을 신뢰할 수 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-12', E'끌려간 남유다 백성에 대한 설득 (예레미야 2장)', E'예레미야 2장', E'예레미야는 하나님께서 주신 말씀을 예루살렘 백성들에게 전합니다. 하나님께서는 이스라엘과의 첫 사랑을 기억하시며, 광야에서 신부가 신랑을 따르듯 하나님을 따랐던 그 시절을 회상하십니다. 이스라엘은 하나님께 드려진 거룩한 첫 열매였고, 그들을 해치는 자는 누구든지 벌을 받았습니다. 그러나 지금 이스라엘은 완전히 달라졌습니다.\n\n하나님께서는 이스라엘의 변절을 두 가지 죄악으로 규정하십니다. "내 백성이 두 가지 악을 행하였나니 곧 그들이 생수의 근원되는 나를 버린 것과 스스로 웅덩이를 판 것인데 그것은 그 물을 가두지 못할 터진 웅덩이들이니라"(렘 2:13). 생수의 근원이신 하나님을 떠나 스스로 만든 우상을 섬기는 것은 터진 웅덩이에 물을 담으려는 어리석은 행위와 같습니다.\n\n이스라엘의 지도자들도 타락했습니다. 제사장들은 여호와를 찾지 않고, 율법을 다루는 자들은 하나님을 알지 못하며, 관리들은 하나님께 반역하고, 선지자들은 바알의 이름으로 예언합니다. 하나님께서 순전한 참 종자로 심으신 포도나무가 이방 포도나무의 악한 가지가 되어버린 것입니다.\n\n더욱 안타까운 것은 이스라엘이 자신들의 죄를 인정하지 않는다는 점입니다. 그들은 우상을 아버지라 부르고 돌을 향해 "너는 나를 낳았다"고 고백하면서도, 여전히 자신들은 더럽혀지지 않았다고 주장합니다. 환난이 닥치면 하나님께 구원을 요청하지만, 평안할 때는 하나님을 잊어버립니다. 처녀가 패물을 잊을 수 없고 신부가 예복을 잊을 수 없듯이, 하나님의 백성이 하나님을 잊는다는 것은 있을 수 없는 일입니다.\n\n하나님께서는 이스라엘의 회개를 간절히 원하십니다. 애굽과 앗수르를 의지하며 정치적 해결책을 찾아 헤매는 그들에게, 진정한 해결은 생수의 근원이신 하나님께로 돌아오는 것임을 깨닫기를 바라십니다.', E'오늘의 핵심\n하나님께서는 생수의 근원이신 자신을 버리고 터진 웅덩이 같은 우상을 섬기는 이스라엘의 영적 간음을 책망하시며, 그들이 회개하고 돌아오기를 간절히 원하십니다.\n\n묵상 질문\n1. 나는 생수의 근원이신 하나님보다 터진 웅덩이 같은 것들을 의지하고 있지는 않은가?\n2. 환난 때만 하나님을 찾고 평안할 때는 하나님을 잊어버리는 이스라엘의 모습이 나의 모습은 아닌가?\n3. 하나님과의 첫사랑을 회복하기 위해 내가 버려야 할 우상은 무엇인가?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-13', E'끌려간 남유다 백성에 대한 설득 (예레미야 3장)', E'예레미야 3장', E'예레미야 3장은 하나님과 이스라엘의 관계를 부부 관계에 비유하여 보여줍니다. 하나님께서는 이스라엘을 간음한 아내로, 자신을 버림받은 남편으로 묘사하시면서도 여전히 돌아오기를 간절히 바라시는 마음을 드러내십니다. \n\n북이스라엘이 우상숭배로 인해 앗수르에 멸망당한 것을 보고도 남유다는 교훈을 얻지 못했습니다. 오히려 "반역한 유다"는 "배역한 이스라엘"보다 더 악했다고 하나님께서는 평가하십니다. 형식적인 종교 개혁을 하면서도 진심으로 돌아오지 않았기 때문입니다. 높은 산과 푸른 나무 아래에서 행하는 우상숭배는 영적 간음이었고, 이는 언약 관계를 파기하는 배신 행위였습니다.\n\n그러나 놀랍게도 하나님께서는 "배역한 자식들아 돌아오라 나는 너희 남편임이라"(14절)고 말씀하십니다. 이혼서까지 주었던 이스라엘을 다시 받아주시겠다는 것입니다. 율법에 따르면 한 번 이혼한 아내가 다른 남자와 결혼했다가 다시 돌아오는 것은 가증한 일이었지만, 하나님의 사랑은 율법을 뛰어넘습니다. \n\n하나님께서는 회복의 약속을 구체적으로 제시하십니다. 마음에 합한 목자들을 세우시고, 예루살렘이 여호와의 보좌가 되며, 남북이 하나 되어 약속의 땅으로 돌아올 것입니다. 특히 언약궤를 더 이상 기억하지 않을 것이라는 말씀은 외적 종교에서 내적 신앙으로의 전환을 암시합니다. 이 모든 회복의 출발점은 "네 죄를 자복하라"(13절)는 하나님의 부르심에 응답하는 것입니다. 죄를 인정하고 돌아올 때, 하나님께서는 배역함을 고치시고 새로운 관계를 시작하십니다.', E'오늘의 핵심\n하나님께서는 영적 간음으로 떠난 이스라엘을 여전히 사랑하시며, 진정한 회개를 통해 돌아오기를 간절히 기다리십니다.\n\n묵상 질문\n1. 나는 형식적 신앙생활을 하면서도 진심으로 돌아왔다고 착각하고 있지는 않은가?\n2. 하나님의 용서가 율법을 넘어서는 은혜임을 깨달을 때 어떤 변화가 일어날까?\n3. "네 죄를 자복하라"는 부르심 앞에 내가 인정해야 할 것은 무엇인가?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-14', E'무너지는 예루살렘 (예레미야애가 1장)', E'예레미야애가 1장', E'예레미야애가는 예루살렘 성이 무너진 후 그 처참한 광경을 바라보며 아파한 예레미야의 슬픔 노래입니다. 왕과 많은 백성이 바벨론으로 끌려가고, 성안에서도 많은 사람이 죽임을 당했습니다. 한때 사람들로 북적이던 도성이 이제는 과부처럼 외로이 앉아 밤새 슬피 우는 모습으로 묘사됩니다. 사랑하던 이웃 나라들 중에 위로하는 자가 하나도 없고, 오히려 동맹국들마저 배반하여 원수가 되었습니다.\n\n이 비극적 상황의 원인을 예레미야는 분명히 밝힙니다. "예루살렘이 크게 범죄함으로 조소거리가 되었으니"(애 1:8)라는 고백처럼, 이 모든 고난은 하나님께 대한 반역의 결과였습니다. 제사장들과 장로들은 양식을 구하다가 성 가운데서 기절하고, 처녀들과 청년들은 사로잡혀 갔습니다. 한때 영광스러웠던 예루살렘의 지도자들은 이제 꼴을 찾지 못한 사슴처럼 힘없이 도망치는 신세가 되었습니다.\n\n예레미야의 애가에서 특별히 주목할 것은 하나님의 의로우심에 대한 인정입니다. "여호와는 의로우시도다 그러나 내가 그의 명령을 거역하였도다"라는 고백은 이 모든 심판이 정당함을 인정하는 신앙의 고백입니다. 동시에 예레미야는 하나님께 간절히 호소합니다. 자신들의 고통을 돌아보시고, 원수들이 기뻐하는 이 상황에서 긍휼을 베풀어 주시기를 간구합니다.\n\n하나님과의 만남의 상징이자 생명의 상징이었던 예루살렘의 멸망을 보며 예레미야가 흘리는 눈물은 곧 하나님의 눈물과도 같았습니다. 항복하라는 예레미야의 예언을 멸시하던 지도자들은 어디에도 보이지 않고, 모욕과 비방을 들으면서도 끝까지 하나님의 말씀을 외치던 선지자만이 잿더미가 된 성읍을 배회하며 울부짖고 있습니다. 그의 눈물은 단순한 감상이 아니라 하나님의 마음을 품은 중보자의 눈물이었습니다.', E'오늘의 핵심\n예루살렘의 멸망은 하나님께 대한 반역의 결과였지만, 예레미야는 하나님의 의로우심을 인정하면서도 긍휼을 구하는 신앙의 균형을 보여줍니다.\n\n묵상 질문\n1. 내 삶의 어려움 속에서도 하나님의 의로우심을 인정할 수 있나요?\n2. 죄의 결과로 인한 고통 속에서도 하나님께 긍휼을 구하고 있나요?\n3. 공동체의 아픔을 나의 아픔으로 품고 중보하는 마음이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-15', E'무너지는 예루살렘 (예레미야애가 2장)', E'예레미야애가 2장', E'예레미야애가 2장은 예루살렘 성의 파괴를 목도한 예레미야가 하나님의 진노를 생생하게 묘사하는 애가입니다. "슬프다"로 시작되는 이 탄식의 노래는 한때 아름답고 영광스러웠던 시온이 하나님의 심판으로 완전히 무너진 모습을 그려냅니다. 하나님께서는 진노하셔서 성전과 성벽을 무너뜨리시고, 왕과 제사장을 버리시며, 절기와 안식일마저 잊어버리게 하셨습니다.\n\n예레미야의 눈에 비친 예루살렘의 모습은 참혹하기 그지없습니다. 한때 "온전한 영광"이요 "모든 세상 사람들의 기쁨"이라 불리던 도성이 이제는 원수들의 조롱거리가 되었습니다. 성읍 길거리에는 굶주림으로 기절하는 어린아이들과 젖먹이들이 널려 있고, 그들은 어머니 품에서 숨을 거두며 "곡식과 포도주가 어디 있느냐"고 묻습니다. 이 처참한 광경 앞에서 선지자는 자신의 창자가 끊어지고 간이 땅에 쏟아지는 듯한 고통을 느낍니다.\n\n특별히 주목할 점은 이 모든 재앙이 바벨론의 공격 때문이 아니라 하나님께서 직접 행하신 일이라는 사실입니다. 하나님께서 "원수같이" 되어 이스라엘을 삼키시고, 마치 활을 당기듯 심판의 화살을 쏘셨다는 표현은 언약 백성을 향한 하나님의 진노가 얼마나 크셨는지를 보여줍니다. 거짓 평안을 전하던 선지자들의 헛된 예언과 백성들의 완고한 불순종이 결국 이런 비극을 초래했던 것입니다.\n\n그러나 예레미야는 절망 가운데서도 기도를 멈추지 않습니다. "네 마음을 주의 얼굴 앞에 물 쏟듯 할지어다"라는 권면은 가장 어두운 심판의 때에도 하나님께 나아가는 것만이 유일한 소망임을 일깨워 줍니다. 비록 지금은 하나님의 진노로 모든 것이 무너졌지만, 그 하나님께 부르짖는 것 외에는 다른 길이 없음을 예레미야는 알고 있었습니다.', E'오늘의 핵심\n하나님께서는 언약을 배반한 백성들에게 철저한 심판을 행하셨지만, 예레미야는 그 절망적인 상황에서도 하나님께 부르짖으며 회복의 소망을 포기하지 않았습니다.\n\n묵상 질문\n1. 하나님의 심판이 이토록 철저했던 이유는 무엇이며, 오늘 나에게 주시는 경고는 무엇일까요?\n2. 가장 어려운 상황에서도 하나님께 나아가는 것이 유일한 길임을 믿고 있나요?\n3. 내 삶에서 하나님보다 더 의지하고 있는 거짓 평안은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-17', E'주의 인자와 긍휼 (예레미야애가 3장)', E'예레미야애가 3장', E'예레미야는 심연에서 부르짖습니다. "여호와의 분노의 매로 말미암아 고난 당한 자는 나로다"(애 3:1). 예루살렘 멸망의 참상을 목격한 선지자의 탄식은 생생한 고통의 언어로 가득합니다. 어둠, 사슬, 눈물, 조롱이 그를 둘러쌉니다. 하나님께서 활을 당겨 자신을 과녁으로 삼으셨다는 표현은 그가 느끼는 절망의 깊이를 보여줍니다. 급기야 18절에서 그는 "나의 힘과 여호와께 대한 내 소망이 끊어졌다"고 고백합니다. 하나님의 선지자가 하나님께 대한 소망이 끊어졌다고 말하는 이 역설적 상황이 바로 인간이 경험할 수 있는 가장 깊은 영적 어둠입니다.\n\n그런데 21절부터 놀라운 전환이 일어납니다. "이것을 내가 내 마음에 담아 두었더니 그것이 오히려 나의 소망이 되었사옴은." 무엇이 그의 소망이 되었을까요? 바로 우리가 ''진멸되지 아니함''입니다. 예루살렘은 폐허가 되었지만, 백성이 완전히 사라지지는 않았습니다. 포로로 끌려갔지만 남은 자가 있었습니다. 예레미야는 이 작은 틈새에서 하나님의 인자와 긍휼을 발견합니다. "여호와의 인자와 긍휼이 무궁하시므로 우리가 진멸되지 아니함이니이다. 이것들이 아침마다 새로우니 주의 성실하심이 크시도소이다"(22-23절).\n\n특별히 33절의 고백이 우리 가슴을 울립니다. "주께서 인생으로 고생하게 하시며 근심하게 하심은 본심이 아니시로다." 하나님의 본심은 고통을 주시는 것이 아니라는 것입니다. 징계 가운데서도 긍휼을 베푸시고, 심판 속에서도 회복의 씨앗을 남기시는 분이 우리 하나님이십니다. 예레미야는 이 진리를 붙잡고 40절에서 권면합니다. "우리가 스스로 우리의 행위들을 조사하고 여호와께로 돌아가자."\n\n오늘 우리도 깊은 고통 속에 있을 수 있습니다. 기도해도 응답이 없고, 하늘이 닫힌 것처럼 느껴질 때가 있습니다. 그러나 예레미야가 발견한 것처럼, 완전히 끝난 것 같은 상황에서도 하나님은 작은 소망의 빛을 남겨두십니다. 그 빛은 아침마다 새로운 하나님의 인자하심입니다. 어제의 실패가 오늘의 은혜를 막을 수 없습니다. 지금 내게 남아 있는 것이 무엇인지 돌아보십시오. 그 작은 것 속에 담긴 하나님의 긍휼을 발견하시길 바랍니다.', E'오늘의 핵심\n예레미야는 절망의 바닥에서도 ''진멸되지 아니함''이라는 작은 틈새를 통해 하나님의 무궁한 인자와 긍휼을 발견하고, 아침마다 새로운 주의 성실하심을 고백합니다.\n\n묵상 질문\n1. 내 인생의 가장 깊은 절망 속에서 하나님은 어떤 작은 소망을 남겨두셨나요?\n2. ''아침마다 새로운'' 하나님의 인자하심을 오늘 어떻게 경험할 수 있을까요?\n3. 고통이 하나님의 본심이 아니라면, 내 고난을 통해 하나님이 이루실 선한 뜻은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-18', E'주의 인자와 긍휼 (예레미야애가 4장)', E'예레미야애가 4장', E'예레미야애가 4장은 예루살렘 멸망의 처참한 현실을 가장 생생하게 보여줍니다. "슬프다 어찌 그리 금이 빛을 잃고 순금이 변질하였으며"라는 탄식으로 시작되는 이 장은 한때 영광스러웠던 도시의 비참한 몰락을 그립니다. 성전의 금과 보석들이 거리에 흩어진 것처럼, 하나님의 백성들도 그 존귀함을 잃고 질그릇처럼 버려졌습니다.\n\n특히 가슴 아픈 것은 아이들의 고통입니다. 젖먹이들이 목말라 혀가 입천장에 붙고, 어린아이들이 떡을 구해도 줄 사람이 없다는 묘사는 도시가 얼마나 철저히 파괴되었는지를 보여줍니다. 더 충격적인 것은 10절의 기록입니다. 극심한 기근으로 자비로운 어머니들조차 자기 자녀를 삶아 먹었다는 것입니다. 이는 신명기 28장에 예언된 언약의 저주가 그대로 성취된 것이었습니다.\n\n그런데 예레미야는 이 비극의 근본 원인을 13절에서 분명히 밝힙니다. "그의 선지자들의 죄들과 제사장들의 죄악들 때문이니." 영적 지도자들이 먼저 타락했고, 의인들의 피를 흘렸습니다. 하나님의 말씀을 전해야 할 선지자들이 거짓을 말했고, 거룩함을 지켜야 할 제사장들이 불의를 행했습니다. 지도자들의 실패가 온 공동체를 멸망으로 이끌었던 것입니다.\n\n17절은 또 다른 교훈을 줍니다. "우리를 구원하지 못할 나라를 바라보고 바라보았도다." 유다는 애굽의 도움을 기대했지만 헛된 소망이었습니다. 하나님을 떠나 세상 권력을 의지한 결과는 철저한 배신과 실망뿐이었습니다. 그들이 의지했던 왕조차 20절에서 보듯이 적의 함정에 빠지고 말았습니다.\n\n그러나 예레미야는 22절에서 희망의 빛을 비춥니다. "딸 시온아 네 죄악의 형벌이 다하였으니." 심판은 영원하지 않습니다. 하나님의 징계에는 끝이 있으며, 회복의 날이 올 것입니다. 비록 지금은 폐허가 되었지만, 하나님께서는 당신의 백성을 완전히 버리지 않으셨습니다. 오히려 이 철저한 심판을 통해 새로운 시작을 준비하고 계셨던 것입니다.', E'오늘의 핵심\n영적 지도자들의 타락이 공동체 전체를 멸망으로 이끌었지만, 하나님께서는 심판 가운데서도 형벌의 끝과 회복의 소망을 약속하십니다.\n\n묵상 질문\n1. 영적 지도자의 책임이 왜 그토록 무거운 것일까요?\n2. 내가 하나님보다 더 의지하고 있는 ''애굽''은 무엇인가요?\n3. 징계 가운데서도 끝이 있다는 하나님의 약속이 내게 어떤 위로가 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-19', E'주의 인자와 긍휼 (예레미야애가 5장)', E'예레미야애가 5장', E'예레미야애가의 마지막 장은 기도로 시작합니다. "여호와여 우리가 당한 것을 기억하시고 우리가 받은 치욕을 살펴보옵소서"(1절). 이 간절한 호소에는 예루살렘 멸망 이후 백성들이 겪어야 했던 처참한 현실이 담겨 있습니다. 기업이 외인들에게 넘어가고, 집들은 이방인들이 차지했습니다. 더 아픈 것은 그들 스스로를 "아버지 없는 고아들"이요 "과부들"로 표현하는 대목입니다. 하나님과의 관계가 단절된 것 같은 영적 고아 상태를 토로하는 것입니다.\n\n생존을 위한 몸부림도 처절합니다. 물 한 모금도 돈을 주고 사 마셔야 하고, 나무 하나도 값을 치러야 얻을 수 있습니다. 애굽과 앗수르에 손을 내밀어 구걸하듯 양식을 구하는 모습은, 한때 젖과 꿀이 흐르는 약속의 땅에 살던 그들에게는 치욕스러운 일이었을 것입니다. 예레미야는 이 모든 고통의 원인을 정확히 직시합니다. "우리의 머리에서는 면류관이 떨어졌사오니 오호라 우리의 범죄 때문이니이다"(16절). 조상들의 죄와 자신들의 죄가 이 모든 비극을 불러왔음을 인정하는 것입니다.\n\n그러나 이 애가의 절정은 19절에서 시작됩니다. "여호와여 주는 영원히 계시오며 주의 보좌는 대대에 이르나이다." 폐허가 된 예루살렘, 무너진 성전을 보면서도 예레미야는 변하지 않는 한 가지를 붙잡습니다. 하나님의 영원하심과 그분의 주권입니다. 그리고 가장 아름다운 기도가 이어집니다. "여호와여 우리를 주께로 돌이키소서 그리하시면 우리가 주께로 돌아가겠사오니"(21절). \n\n이 기도에는 깊은 신학이 담겨 있습니다. 인간의 회개조차 하나님의 은혜가 먼저 있어야 가능하다는 고백입니다. 하나님께서 먼저 우리를 돌이키실 때, 비로소 우리도 돌아갈 수 있습니다. 이것이 바로 하나님의 선행은총입니다. 예레미야애가는 22절의 불확실한 탄식으로 끝나지만, 이미 21절의 기도 속에 소망의 씨앗이 심어져 있습니다. 하나님의 신실하심을 믿는 자의 기도는 결코 헛되지 않을 것입니다.', E'오늘의 핵심\n예레미야는 처참한 현실 속에서도 영원하신 하나님의 주권을 붙잡고, 회개조차 하나님의 은혜로만 가능함을 고백하며 회복을 간구합니다.\n\n묵상 질문\n1. 고통의 원인을 인정하면서도 하나님께 나아갈 수 있는 이유는 무엇일까요?\n2. "우리를 주께로 돌이키소서"라는 기도가 내 삶에 필요한 영역은 어디인가요?\n3. 변하는 상황 속에서도 변하지 않는 하나님의 속성을 어떻게 붙잡을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-20', E'다윗의 내각과 성전 건축 준비 (역대상 23장)', E'역대상 23장', E'다윗이 나이가 많아 늙으매 아들 솔로몬을 이스라엘 왕으로 삼고 이스라엘의 모든 방백과 제사장과 레위 사람을 모았습니다. 왕위 계승을 앞둔 다윗이 가장 먼저 한 일은 레위인들의 조직을 정비하는 것이었습니다. 삼십 세 이상의 레위인을 계수하니 삼만 팔천 명이었는데, 그중 이만 사천 명은 성전 일을 보살피고, 육천 명은 관원과 재판관으로, 사천 명은 문지기로, 사천 명은 찬양하는 자로 배치했습니다. 이는 단순한 행정 정리가 아니라 하나님을 섬기는 일을 국가의 중심에 두겠다는 다윗의 신앙적 결단이었습니다.\n\n본문은 레위 지파를 게르손, 그핫, 므라리의 세 가문으로 나누어 각각의 계보와 우두머리들을 상세히 기록합니다. 특히 주목할 것은 아론의 자손들이 "영원토록 심히 거룩한 자가 되어 여호와 앞에 분향하고 섬기며 영원토록 그 이름으로 축복하게 되었다"는 점입니다. 하나님의 사람 모세의 자손들도 레위 지파 중에 기록되어 함께 성전 봉사에 참여했습니다. 이렇게 각 가문의 역할과 위치가 명확히 정해진 것은 질서 있는 예배 공동체를 만들기 위함이었습니다.\n\n다윗은 레위인의 봉사 연령을 삼십 세에서 이십 세로 낮추었습니다. "이스라엘 하나님 여호와께서 평강을 그의 백성에게 주시고 예루살렘에 영원히 거하시나니 레위 사람이 다시는 성막과 그 가운데에서 쓰는 모든 기구를 멜 필요가 없다"는 것이 그 이유였습니다. 광야에서 성막을 운반하던 시대는 끝났고, 이제는 예루살렘 성전에서 안정적으로 하나님을 섬길 수 있게 되었다는 의미입니다. 레위인들의 새로운 직무는 제사장들을 도와 성전과 뜰과 골방에서 섬기고, 모든 성물을 정결하게 하며, 진설병과 소제물을 준비하고, 아침저녁으로 감사와 찬송을 드리는 것이었습니다.\n\n늙은 왕이 마지막으로 정비한 것이 예배 조직이었다는 사실은 우리에게 깊은 교훈을 줍니다. 다윗은 정치적 안정이나 경제적 번영보다 하나님을 섬기는 일을 최우선으로 여겼습니다. 오늘 우리의 삶에서도 가장 중요한 것은 하나님께 드리는 예배입니다. 내 삶의 우선순위가 어디에 있는지, 하나님을 섬기는 일에 얼마나 마음을 쏟고 있는지 돌아보게 됩니다.', E'오늘의 핵심\n다윗은 왕위 계승을 앞두고 레위인들의 봉사 조직을 체계적으로 정비함으로써 하나님을 섬기는 일이 국가의 중심임을 분명히 했습니다.\n\n묵상 질문\n1. 다윗이 생의 마지막에 예배 조직 정비를 최우선으로 한 이유는 무엇일까요?\n2. 내 삶의 우선순위에서 하나님을 섬기는 일은 어느 자리에 있나요?\n3. 다음 세대가 하나님을 잘 섬길 수 있도록 내가 준비해야 할 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-21', E'다윗의 내각과 성전 건축 준비 (역대상 24장)', E'역대상 24장', E'다윗이 성전 건축을 위해 준비한 것은 단지 물질적인 재료만이 아니었습니다. 역대상 24장은 제사장들의 봉사 조직을 정비하는 모습을 보여주고 있습니다. 아론의 후손들을 24반차로 나누어 성전에서 섬기도록 한 것입니다. 이는 단순한 행정적 조치가 아니라, 하나님을 섬기는 일에 질서와 공정함을 세우려는 영적 개혁이었습니다.\n\n본문은 나답과 아비후가 일찍 죽은 후 엘르아살과 이다말의 후손들이 제사장 직분을 이어받았다고 전합니다. 다윗은 이들을 차별 없이 제비뽑기로 나누어 각자의 직무를 정했습니다. "이에 제비 뽑아 피차에 차등이 없이 나누었으니"(대상 24:5)라는 말씀은 하나님 앞에서 모든 봉사자가 동등함을 보여줍니다. 엘르아살의 후손이 더 많았지만, 제비뽑기를 통해 하나님의 주권에 맡긴 것입니다.\n\n이러한 조직 정비가 필요했던 이유는 무엇일까요. 다윗 시대에 이르러 제사장의 수가 크게 늘어났고, 곧 세워질 성전에서 체계적으로 봉사하려면 명확한 질서가 필요했기 때문입니다. 24반차로 나누어진 제사장들은 일 년을 돌아가며 성전에서 섬기게 되었습니다. 이는 모든 제사장에게 봉사의 기회를 공평하게 주면서도, 성전 예배가 중단 없이 지속되도록 하는 지혜로운 방법이었습니다.\n\n특별히 주목할 것은 이 모든 과정이 왕과 제사장, 레위인의 지도자들이 함께 모인 자리에서 공개적으로 이루어졌다는 점입니다. 서기관 스마야가 그들의 이름을 하나하나 기록했습니다. 이는 하나님의 일을 투명하고 공정하게 처리하려는 다윗의 의지를 보여줍니다.\n\n오늘날 교회에서도 봉사와 섬김의 자리를 놓고 갈등이 생기곤 합니다. 누가 더 중요한 일을 하는가, 누가 더 눈에 띄는 자리에 서는가를 두고 경쟁하기도 합니다. 그러나 다윗이 보여준 원칙은 분명합니다. 하나님을 섬기는 일에는 높고 낮음이 없으며, 모든 봉사는 하나님 앞에서 동등하게 귀한 것입니다. 중요한 것은 각자 맡은 자리에서 신실하게 섬기는 것입니다.', E'오늘의 핵심\n다윗은 제사장들을 24반차로 공정하게 조직하여, 하나님을 섬기는 일에 질서를 세우고 모든 이에게 동등한 봉사의 기회를 주었습니다.\n\n묵상 질문\n1. 하나님의 일을 섬길 때 제비뽑기로 공정하게 나눈 다윗의 지혜에서 무엇을 배울 수 있을까요?\n2. 내가 섬기는 자리가 작고 보잘것없어 보일 때, 하나님은 그 봉사를 어떻게 보실까요?\n3. 교회 안에서 질서와 공평함을 세우기 위해 내가 할 수 있는 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-22', E'다윗의 내각과 성전 건축 준비 (역대상 25장)', E'역대상 25장', E'다윗이 성전 예배를 위해 준비한 것 중에서 가장 혁신적인 것은 찬양대의 조직이었습니다. 역대상 25장은 아삽과 헤만과 여두둔의 자손들로 구성된 찬양대가 어떻게 조직되었는지를 상세히 보여줍니다. 흥미로운 것은 다윗이 이들을 단순히 음악가로 세운 것이 아니라 "신령한 노래"를 하는 자들로 구별했다는 점입니다. 찬양은 단순한 음악 활동이 아니라 영적인 사역이었던 것입니다.\n\n본문은 이들을 "하나님의 말씀을 가진 왕의 선견자"(25:5)라고 부르며, 그들의 찬양이 예언적 성격을 띠고 있었음을 암시합니다. 실제로 아삽과 헤만과 여두둔은 다윗과 함께 많은 시편을 기록한 인물들이었습니다. 그들은 수금과 비파와 제금을 연주하며 하나님께 감사와 찬양을 올려드렸고, 이는 이스라엘 예배의 중요한 부분이 되었습니다.\n\n특별히 주목할 것은 이들이 제비뽑기로 직무를 배정받았다는 사실입니다. "큰 자나 작은 자나 스승이나 제자를 막론하고" 동등하게 제비를 뽑았다는 것은 하나님 앞에서 모든 봉사자가 평등함을 보여줍니다. 288명이라는 숙련된 찬양대원들이 24개 반으로 나뉘어 각각 12명씩 봉사했는데, 이는 제사장들의 24반차와 일치하는 체계적인 조직이었습니다.\n\n다윗은 찬양을 통해 하나님의 임재를 경험했던 사람이었습니다. 광야에서 양을 치며 수금을 타던 소년이 이제는 온 이스라엘의 찬양 체계를 세우는 왕이 되었습니다. 그는 자신이 경험한 찬양의 능력을 다음 세대가 계속 이어가기를 원했고, 그래서 이토록 정교한 찬양 조직을 만든 것입니다.\n\n오늘날 우리의 예배에서도 찬양은 여전히 중요한 위치를 차지합니다. 찬양은 단순한 예배 순서의 하나가 아니라 하나님께 나아가는 영적 통로입니다. 다윗이 찬양대를 "신령한 노래를 하는 자들"로 구별한 것처럼, 우리도 찬양을 영적 사역으로 인식하고 온 마음을 다해 하나님을 높여드려야 할 것입니다.', E'오늘의 핵심\n다윗은 성전 예배를 위해 288명의 전문 찬양대를 24반으로 조직하여, 찬양을 통한 예배가 체계적이고 지속적으로 이루어지도록 준비했습니다.\n\n묵상 질문\n1. 다윗이 찬양대를 "신령한 노래를 하는 자들"로 구별한 의미는 무엇일까요?\n2. 내 삶에서 찬양은 어떤 의미를 가지고 있으며, 얼마나 정성을 다하고 있나요?\n3. 하나님께서 나에게 주신 은사로 예배 공동체를 섬길 수 있는 방법은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-24', E'다윗의 내각과 성전 건축 준비 (역대상 26장)', E'역대상 26장', E'다윗은 성전을 짓지 못하게 되었지만, 미래의 성전을 위해 철저한 준비를 계속했습니다. 역대상 26장은 성전 문지기와 곳간 관리자들의 조직을 보여주는데, 이는 단순한 행정 명단이 아니라 다윗이 얼마나 세심하게 하나님의 집을 준비했는지를 드러냅니다.\n\n문지기의 직분은 고라와 므라리 자손들에게 맡겨졌습니다. 특별히 오벧에돔의 가문이 주목되는데, "하나님이 오벧에돔에게 복을 주셨음이라"(대상 26:5)는 기록이 이를 증명합니다. 법궤를 석 달 동안 모셨던 오벧에돔의 가문은 이제 성전의 문을 지키는 영광스러운 직분을 받게 되었습니다. 그의 자손 62명이 모두 능력 있는 자들로 성전을 섬기게 된 것은 하나님께서 주신 복의 연속이었습니다.\n\n문지기들은 제비를 뽑아 동서남북 각 문과 곳간을 맡았습니다. 이들의 역할은 단순히 문을 여닫는 것이 아니었습니다. 하나님의 집을 거룩하게 지키고, 예배자들이 합당한 마음으로 들어오도록 돕는 영적 파수꾼이었습니다. 또한 레위인들은 성전의 곳간을 관리했는데, 여기에는 다윗과 지도자들이 전쟁에서 얻은 전리품을 구별하여 드린 것들이 보관되었습니다. 승리의 영광을 자신의 것으로 삼지 않고 하나님께 돌린 것입니다.\n\n주목할 점은 성전 밖의 일을 맡은 이들도 있었다는 것입니다. 이스할 자손들은 관원과 재판관이 되어 백성들의 일상에서 하나님의 공의를 실현했고, 헤브론 자손들은 요단 서쪽 지역에서 "여호와의 모든 일과 왕을 섬기는 직임"을 맡았습니다. 성전 안의 예배와 성전 밖의 삶이 하나로 연결되어 있음을 보여줍니다.\n\n다윗이 세운 이 조직은 하나님 나라의 질서가 어떠해야 하는지를 보여줍니다. 각자의 은사와 소명에 따라 맡은 자리에서 충성하되, 모든 일의 중심에는 하나님을 섬기는 마음이 있어야 합니다. 오늘날 교회 공동체도 마찬가지입니다. 보이는 곳에서 섬기든 보이지 않는 곳에서 섬기든, 우리 모두는 하나님 나라의 일꾼입니다.', E'오늘의 핵심\n다윗은 성전 문지기와 곳간 관리자들을 세심하게 조직하여, 미래의 성전이 질서 있게 운영되도록 준비했으며, 이는 하나님 나라의 질서가 예배를 중심으로 세워져야 함을 보여줍니다.\n\n묵상 질문\n1. 오벧에돔처럼 과거의 축복이 현재의 섬김으로 이어지는 경험이 내게도 있나요?\n2. 내가 맡은 작은 일도 하나님 나라를 세우는 중요한 역할임을 인식하고 있나요?\n3. 성전 안의 예배와 일상의 삶이 하나로 연결되어 있다면, 오늘 내 일터에서 어떻게 하나님을 섬길 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-25', E'다윗의 내각과 성전 건축 준비 (역대상 27장)', E'역대상 27장', E'다윗의 통치 말년, 그가 이스라엘을 위해 남긴 마지막 유산은 단순한 조직도가 아니었습니다. 역대상 27장에는 군대의 월별 근무 체계, 각 지파의 지도자들, 그리고 왕실 재산 관리자들의 명단이 빼곡히 기록되어 있습니다. 이 세밀한 기록들은 다윗이 얼마나 치밀하게 나라의 기틀을 다졌는지를 보여줍니다. 각 달마다 2만 4천 명씩 교대로 복무하는 군사 조직은 백성들의 부담을 줄이면서도 국방력을 유지할 수 있는 지혜로운 제도였습니다.\n\n특별히 주목할 것은 다윗이 20세 이하의 인구조사를 하지 않았다는 기록입니다. "여호와께서 전에 말씀하시기를 이스라엘 사람을 하늘의 별 같이 많게 하리라 하셨음이라"(대상 27:23)는 구절은 다윗이 과거의 실수를 되풀이하지 않으려 했음을 보여줍니다. 요압이 시작한 인구조사로 인해 진노가 임했던 아픈 기억을 간직한 채, 다윗은 하나님의 약속을 신뢰하는 법을 배웠습니다.\n\n왕실 재산 관리 체계 역시 인상적입니다. 곳간, 포도원, 감람나무, 가축에 이르기까지 각 분야의 전문가들이 배치되었습니다. 이는 단순히 왕의 부를 관리하는 것이 아니라, 나라 전체의 경제 기반을 튼튼히 하려는 의도였습니다. 다윗은 자신의 개인적 영광이 아니라 이스라엘 공동체 전체의 안정과 번영을 위해 일했던 것입니다.\n\n다윗의 조직 편성에서 우리가 배울 것은 하나님의 일에도 질서와 체계가 필요하다는 사실입니다. 영적인 열정만으로는 부족합니다. 각자의 은사에 따라 적재적소에 배치하고, 서로의 짐을 나누어 지며, 다음 세대까지 이어질 수 있는 견고한 토대를 놓아야 합니다. 오늘 우리에게 맡겨진 작은 일도 하나님 나라의 큰 그림 속에서 귀한 역할을 감당하고 있음을 기억하시기 바랍니다.', E'오늘의 핵심\n다윗은 군사 조직과 행정 체계를 세밀하게 정비하면서도 하나님의 약속을 신뢰하는 믿음을 잃지 않았으며, 개인의 영광이 아닌 공동체 전체의 유익을 추구했습니다.\n\n묵상 질문\n1. 다윗이 20세 이하 인구조사를 하지 않은 이유에서 우리가 배울 믿음의 자세는 무엇일까요?\n2. 내가 속한 공동체에서 질서와 체계를 세우면서도 하나님을 의지하려면 어떻게 해야 할까요?\n3. 오늘 내게 맡겨진 작은 일이 하나님 나라에 어떤 의미가 있을지 묵상해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-26', E'히스기야의 회개와 므낫세의 죄악 (역대하 32장)', E'역대하 32장', E'앗수르의 대군이 유다를 향해 밀려오는 절체절명의 순간, 히스기야는 인간적인 대비와 함께 더 중요한 영적 준비를 했습니다. 물 근원을 막고 성벽을 보수하며 무기를 만들었지만, 그의 진짜 무기는 하나님께 대한 신뢰였습니다. "우리와 함께 하시는 이는 우리의 하나님 여호와시라 반드시 우리를 도우시고 우리를 대신하여 싸우시리라"(대하 32:8). 이 선포는 백성들에게 큰 위로가 되었고, 실제로 하나님께서는 천사를 보내어 앗수르 군대를 멸하심으로써 히스기야의 믿음이 헛되지 않았음을 증명하셨습니다.\n\n그런데 위기가 지나고 평안과 번영이 찾아오자 히스기야에게 예상치 못한 시험이 찾아왔습니다. 죽을 병에서 기적적으로 회복되고, 열방이 보물을 바치며 존귀하게 여기는 상황에서 그의 마음에 교만이 싹튼 것입니다. 특히 바벨론 사신들에게 왕실의 모든 보물을 자랑스럽게 보여준 일은, 하나님보다 자신의 부와 영광을 의지하기 시작했음을 보여줍니다. 다행히 히스기야는 자신의 교만을 깨닫고 회개했고, 하나님께서는 그 겸손함을 받으셨습니다.\n\n히스기야의 이야기는 우리에게 중요한 교훈을 전해줍니다. 위기의 때에는 간절히 하나님을 찾다가도, 형편이 나아지면 은혜를 잊어버리는 것이 우리의 연약함입니다. 물질적 풍요, 사회적 인정, 건강의 회복 같은 축복이 오히려 하나님으로부터 멀어지게 하는 덫이 될 수 있음을 본문은 경고합니다. 진정한 신앙의 성숙은 어려울 때만이 아니라 평안할 때에도 하나님을 기억하고, 받은 은혜에 합당하게 반응하는 것입니다. 오늘 우리의 삶 속에서 감사와 겸손으로 보답해야 할 하나님의 은혜는 무엇인지 돌아보아야 하겠습니다.', E'오늘의 핵심\n히스기야는 국가적 위기 앞에서 하나님을 온전히 신뢰했으나, 평안과 번영 속에서는 교만에 빠졌다가 다시 회개함으로써 신앙의 성숙을 보여주었습니다.\n\n묵상 질문\n1. 내가 지금 당면한 어려움 속에서 인간적인 해결책과 함께 하나님을 먼저 의지하고 있나요?\n2. 형편이 나아진 후에도 그 은혜의 근원이신 하나님을 기억하고 감사하며 살고 있나요?\n3. 히스기야처럼 내 마음의 교만을 인정하고 겸손히 돌이킬 용기가 있는지 점검해 보세요.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-27', E'히스기야의 회개와 므낫세의 죄악 (역대하 33장)', E'역대하 33장', E'히스기야의 신앙 개혁이 유다를 구원으로 이끌었던 그 시대가 막을 내리고, 열두 살의 어린 므낫세가 왕위에 올랐습니다. 그런데 놀랍게도 므낫세는 아버지가 평생 헐어버렸던 산당을 다시 세우고, 바알 제단을 쌓으며, 하늘의 일월성신을 섬기기 시작합니다. 더욱 충격적인 것은 하나님의 성전 안에까지 우상의 제단을 세웠다는 사실입니다. 하나님께서 "내가 내 이름을 예루살렘에 영원히 두리라"(대하 33:4)고 약속하신 바로 그 성전이 우상으로 더럽혀진 것입니다.\n\n므낫세의 악행은 여기서 그치지 않았습니다. 힌놈의 아들 골짜기에서 자기 아들들을 불 가운데로 지나가게 하는 인신제사를 행하고, 점술과 사술에 빠져들었습니다. 성경은 그가 백성을 꾀어 악을 행하게 했는데, 그 정도가 여호와께서 멸하신 가나안 족속들보다 더 심했다고 기록합니다. 한 세대 만에 이스라엘이 가나안 족속보다 더 악해진 것입니다.\n\n하나님께서는 므낫세와 백성들에게 경고하셨지만 그들은 듣지 않았습니다. 결국 하나님은 앗수르 군대를 통해 므낫세를 징계하십니다. 쇠사슬에 묶여 바벨론으로 끌려간 므낫세는 그제야 환난 중에 하나님께 간구하며 크게 겸손해집니다. 놀랍게도 하나님은 이 악한 왕의 기도까지도 들으시고 그를 예루살렘으로 돌아오게 하십니다. "므낫세가 그제서야 여호와께서 하나님이신 줄을 알았더라"(대하 33:13)는 고백이 우리에게 깊은 울림을 줍니다.\n\n돌아온 므낫세는 우상을 제거하고 여호와의 제단을 보수하며 백성들에게 하나님을 섬기라고 명령합니다. 비록 백성들이 여전히 산당에서 제사를 드리는 한계는 있었지만, 적어도 여호와께만 제사를 드리게 되었습니다. 그러나 므낫세의 아들 아몬은 아버지의 악행만을 본받고 회개는 본받지 않았습니다. 겸손하지 않고 더욱 범죄하다가 신하들의 반역으로 죽임을 당합니다.\n\n이 본문은 하나님의 놀라운 은혜와 인간의 책임을 동시에 보여줍니다. 가장 악한 왕조차도 진심으로 회개할 때 용서하시는 하나님의 긍휼하심과, 그럼에도 불구하고 55년간 쌓인 악의 영향력이 쉽게 사라지지 않는 현실을 함께 보여주는 것입니다. 오늘 우리의 선택이 다음 세대에 어떤 유산을 남길지, 진지하게 생각해 보아야 할 때입니다.', E'오늘의 핵심\n므낫세는 아버지 히스기야의 모든 개혁을 무너뜨리고 극악한 우상숭배를 행했지만, 환난 중에 회개하여 하나님의 용서를 받았습니다. 그러나 그의 악행이 남긴 영향은 다음 세대까지 이어졌습니다.\n\n묵상 질문\n1. 므낫세처럼 하나님의 은혜를 경험한 부모 세대의 신앙이 자녀에게 전달되지 않는 이유는 무엇일까요?\n2. 환난 중에야 비로소 하나님을 찾게 되는 우리의 연약함을 어떻게 극복할 수 있을까요?\n3. 내가 지금 행하는 일들이 다음 세대에 어떤 영향을 미칠지 기도하며 점검해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-28', E'요시야의 개혁과 남유다의 최후 (열왕기하 22장)', E'열왕기하 22장', E'여덟 살의 어린 나이에 왕위에 오른 요시야는 하나님 보시기에 정직하게 행하여 그의 조상 다윗의 모든 길로 행하고 좌우로 치우치지 않았습니다. 그의 조부 므낫세가 55년간, 부친 아몬이 2년간 극심한 우상숭배로 유다를 타락시켰던 것과는 정반대의 길이었습니다. 요시야가 왕이 된 지 18년째 되던 해, 그는 오랫동안 방치되었던 성전을 수리하라는 명령을 내립니다. 이 과정에서 놀라운 일이 벌어집니다. 대제사장 힐기야가 성전에서 율법책을 발견한 것입니다.\n\n이 율법책은 아마도 므낫세와 아몬의 악정 기간 동안 숨겨져 있던 것으로 보입니다. 서기관 사반이 왕 앞에서 이 책을 읽자, 요시야는 즉시 자신의 옷을 찢습니다. 이는 극도의 슬픔과 회개의 표현이었습니다. 율법의 말씀이 얼마나 철저히 무시되어 왔는지, 하나님의 뜻에서 얼마나 멀리 떠나 있었는지를 깨달은 것입니다. 요시야는 즉시 제사장들과 신하들을 여선지자 훌다에게 보내 하나님의 뜻을 묻게 합니다.\n\n훌다를 통해 전해진 하나님의 메시지는 엄중했습니다. 백성이 하나님을 버리고 우상을 섬긴 대가로 심판이 임할 것이라는 선언이었습니다. 그러나 동시에 요시야 개인에게는 놀라운 은혜가 주어집니다. "네가 듣고 마음이 부드러워져서 여호와 앞 곧 내 앞에서 겸비하여 옷을 찢고 통곡하였으므로 나도 네 말을 들었노라"(왕하 22:19)는 하나님의 응답이었습니다. 요시야의 진실한 회개와 겸손이 하나님의 마음을 움직인 것입니다.\n\n이 사건은 하나님의 말씀이 가진 능력을 보여줍니다. 오랫동안 잊혀졌던 율법책 하나가 한 나라의 운명을 바꾸는 개혁의 시작점이 되었습니다. 또한 한 사람의 진실한 회개가 얼마나 귀한지를 보여줍니다. 비록 나라 전체의 심판은 피할 수 없었지만, 요시야 개인에게는 평안이 약속되었습니다. 하나님은 지금도 말씀 앞에서 마음이 부드러워지고 겸비해지는 이들의 기도를 들으십니다.', E'오늘의 핵심\n오랫동안 잊혀졌던 율법책의 발견은 요시야로 하여금 진실한 회개에 이르게 했고, 하나님은 그의 겸손한 반응에 응답하셨습니다.\n\n묵상 질문\n1. 내 삶에서 오랫동안 묵혀두었던 하나님의 말씀은 무엇이며, 그것을 어떻게 다시 발견할 수 있을까요?\n2. 요시야처럼 말씀 앞에서 마음이 부드러워지고 옷을 찢을 만큼 애통해한 적이 있나요?\n3. 한 사람의 진실한 회개가 주변에 미치는 영향력에 대해 생각해보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-29', E'요시야의 개혁과 남유다의 최후 (열왕기하 23장)', E'열왕기하 23장', E'성전에서 발견된 율법책이 요시야의 마음을 뜨겁게 했습니다. 왕은 즉시 유다와 예루살렘의 모든 장로들을 소집하고, 대제사장부터 평민에 이르기까지 모든 백성을 여호와의 성전으로 모았습니다. 그리고 성전에서 발견한 언약책의 모든 말씀을 한 구절도 빠짐없이 읽어 들려주었습니다. 단 위에 선 왕은 온 백성 앞에서 여호와와 언약을 세우며 "마음을 다하고 뜻을 다하여 여호와께 순종하고 그의 계명과 법도와 율례를 지켜 이 책에 기록된 이 언약의 말씀을 이루게 하리라"(왕하 23:3)고 선언했습니다.\n\n요시야의 개혁은 말에 그치지 않았습니다. 왕은 성전에서 바알과 아세라, 그리고 일월성신을 위해 만들어진 모든 기구들을 끌어내어 기드론 들판에서 불살랐습니다. 솔로몬 시대부터 예루살렘 동편 감람산에 세워졌던 이방 신들의 산당들도 모두 파괴했습니다. 특별히 벧엘에 있던 여로보암의 제단까지 헐어버림으로써, 북이스라엘을 타락시킨 우상숭배의 뿌리까지 제거했습니다. \n\n개혁의 절정은 유월절 준수였습니다. 사사 시대 이후 수백 년 동안 제대로 지켜지지 않았던 유월절이 율법의 규정대로 온전히 지켜졌습니다. 이는 단순한 종교 행사가 아니라, 이스라엘이 하나님의 백성임을 다시 확인하는 언약 갱신의 축제였습니다. 요시야는 모세의 모든 율법을 따라 마음과 뜻과 힘을 다해 여호와께로 돌이킨 왕이었습니다.\n\n그러나 므낫세가 쌓아올린 죄악의 무게는 너무나 무거웠습니다. 한 사람의 헌신적인 개혁으로도 하나님의 진노를 돌이킬 수 없었습니다. 요시야는 므깃도에서 애굽 왕 바로 느고와 맞서다 전사했고, 그의 죽음과 함께 유다의 마지막 희망도 사라졌습니다. 그럼에도 요시야가 보여준 철저한 회개와 개혁은 어두운 시대에 하나님께서 기뻐하시는 신앙의 본을 남겼습니다.', E'오늘의 핵심\n요시야는 발견된 율법책에 근거하여 철저한 종교개혁을 단행했지만, 유다의 누적된 죄악으로 인한 심판의 운명을 바꿀 수는 없었습니다.\n\n묵상 질문\n1. 요시야처럼 하나님의 말씀을 듣고 즉시 행동으로 옮기는 결단력이 내게는 있나요?\n2. 내 삶과 가정, 공동체에서 제거해야 할 우상들은 무엇인가요?\n3. 한 사람의 헌신이 시대를 바꾸지 못할지라도 끝까지 순종하는 이유는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-01', E'심판을 거부하는 이스라엘 (에스겔 18장)', E'에스겔 18장', E'바빌론 포로 생활의 고단함 속에서 이스라엘 백성들 사이에 한 속담이 돌고 있었습니다. "아버지가 신 포도를 먹었으므로 그의 아들의 이가 시다"(겔 18:2)라는 말이었습니다. 이는 자신들이 겪는 고통의 원인을 조상들의 죄에서 찾으며, 현재의 심판이 부당하다고 항변하는 내용이었습니다. 그러나 하나님께서는 이 속담이 더 이상 쓰이지 못할 것이라고 선언하십니다. 모든 영혼이 하나님께 속하였으며, 각 사람은 자신의 행위에 따라 심판받는다는 것이 하나님의 공의로운 원칙임을 분명히 하십니다.\n\n에스겔을 통해 전해지는 하나님의 말씀은 개인의 책임을 강조합니다. 의로운 아버지가 악한 아들을 낳았다면, 그 아들은 자신의 악행으로 인해 죽을 것이며, 악한 아버지가 의로운 아들을 낳았다면, 그 아들은 아버지의 죄로 인해 죽지 않을 것입니다. 하나님께서는 각 사람의 행위를 따라 심판하시되, 의인의 공의는 그에게로, 악인의 악은 그에게로 돌아간다고 말씀하십니다. 이는 단순히 공정한 심판의 원칙만을 선포하는 것이 아니라, 각 개인에게 회개와 변화의 기회가 열려 있음을 보여주는 은혜의 메시지입니다.\n\n특별히 주목할 것은 하나님의 마음입니다. "내가 어찌 악인이 죽는 것을 조금인들 기뻐하랴"(겔 18:23)라는 말씀에서 드러나듯이, 하나님께서는 심판 자체를 원하시는 것이 아니라 죄인이 돌이켜 생명을 얻기를 간절히 원하십니다. 악인이라도 자신의 모든 죄에서 돌이켜 떠나 하나님의 율례를 지키고 정의와 공의를 행하면 반드시 살 것이라는 약속이 주어집니다. 이는 웨슬리가 강조한 선행은총의 역사입니다. 하나님께서는 먼저 은혜를 베푸시고, 인간이 그 은혜에 응답하여 돌이킬 수 있는 능력을 주십니다. "너희는 돌이켜 회개하고 모든 죄에서 떠날지어다"라는 권면은 명령인 동시에, 그렇게 할 수 있는 은혜가 이미 주어졌음을 전제하는 초대입니다.', E'오늘의 핵심\n하나님께서는 각 사람을 그 행위대로 심판하시되, 악인이라도 돌이켜 회개하면 살리시는 은혜의 하나님이십니다.\n\n묵상 질문\n1. 내 삶의 문제를 다른 사람이나 환경 탓으로 돌리고 있지는 않나요?\n2. 하나님께서 악인의 죽음을 기뻐하지 않으신다면, 나는 어떤 마음으로 죄인을 바라보고 있나요?\n3. 오늘 하나님께서 내게 돌이키라고 부르시는 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-02', E'심판을 거부하는 이스라엘 (에스겔 19장)', E'에스겔 19장', E'에스겔 19장은 이스라엘 고관들을 위한 애가(哀歌)입니다. 하나님께서는 에스겔에게 이스라엘 왕가의 비극적 운명을 노래하라고 명하십니다. 이 애가는 두 가지 상징적 그림을 통해 유다 왕국의 몰락을 묘사합니다.\n\n첫 번째 그림은 암사자와 그 새끼들의 이야기입니다. 암사자는 유다 왕국을, 새끼들은 그 왕들을 가리킵니다. 첫 번째 새끼는 여호아하스 왕으로, 그는 애굽으로 끌려갔습니다. 두 번째 새끼는 여호야긴 왕으로, 바벨론에 포로로 잡혀갔습니다. 사자로 묘사된 이 왕들은 힘과 권세를 가졌지만, 결국 이방 나라들에 의해 잡혀가는 비참한 운명을 맞이했습니다.\n\n두 번째 그림은 포도나무의 비유입니다. 물가에 심겨져 풍성한 열매를 맺던 포도나무는 유다 왕국의 번영을 상징합니다. 그러나 "분노 중에 뽑혀서 땅에 던짐을 당하매"(겔 19:12)라는 표현처럼, 하나님의 심판으로 인해 뿌리째 뽑혀 광야에 버려졌습니다. 한때 왕의 규(圭)가 될 만큼 강했던 가지들은 꺾이고 말라 불에 탔습니다. 이는 시드기야 왕 때 예루살렘이 멸망하고 왕조가 끝나는 것을 예언합니다.\n\n이 애가가 특별한 이유는 단순히 과거를 회상하거나 미래를 예언하는 데 그치지 않기 때문입니다. 에스겔은 이미 일어난 일과 곧 일어날 일을 함께 엮어 하나님의 심판이 얼마나 철저한지를 보여줍니다. 왕들의 포로됨과 왕국의 멸망은 우연이나 불운이 아니라, 하나님께서 그들의 죄악에 대해 내리신 정당한 심판이었습니다.\n\n애가의 마지막 구절 "이것이 애가라 후에도 애가가 되리라"는 이 슬픔이 일시적이지 않음을 암시합니다. 그러나 성경 전체의 맥락에서 볼 때, 하나님의 심판은 결코 끝이 아닙니다. 심판 너머에는 언제나 회복의 소망이 있습니다. 다윗의 보좌는 무너졌지만, 그 줄기에서 새로운 가지가 나실 것입니다. 이것이 바로 메시아를 통한 구원의 약속입니다.', E'오늘의 핵심\n하나님께서는 이스라엘 왕가의 몰락을 애가로 노래하게 하심으로써, 그들의 멸망이 하나님의 정당한 심판임을 선포하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 경고와 징계를 무시하고 있는 영역은 없나요?\n2. 세상의 권세와 힘을 의지하다가 무너진 왕들의 모습이 오늘날 우리에게 주는 교훈은 무엇일까요?\n3. 심판 가운데서도 소망을 잃지 않는 믿음을 어떻게 지킬 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-03', E'심판을 거부하는 이스라엘 (에스겔 20장)', E'에스겔 20장', E'포로로 끌려온 지 7년째 되던 해, 이스라엘의 장로들이 에스겔을 찾아와 하나님의 뜻을 묻고자 했습니다. 그러나 하나님께서는 그들의 물음을 단호히 거절하시며, 오히려 그들 조상들의 죄악의 역사를 낱낱이 드러내라고 명하십니다. 이스라엘의 패역함은 애굽에서부터 시작되었습니다. 하나님께서 그들을 택하시고 젖과 꿀이 흐르는 땅으로 인도하겠다고 약속하셨으나, 그들은 애굽의 우상들을 버리지 않았습니다.\n\n광야에서도 마찬가지였습니다. 하나님께서는 생명을 주는 율례와 규례를 주시고, 안식일을 거룩하게 하는 표징으로 삼으셨습니다. 그러나 이스라엘은 율례를 멸시하고 안식일을 더럽혔습니다. 하나님께서는 진노하셨지만 자신의 이름을 위하여 그들을 멸하지 않으셨습니다. 이방인들이 보는 앞에서 하나님의 이름이 욕되지 않게 하려는 거룩한 열심 때문이었습니다.\n\n더욱 안타까운 것은 광야에서 자란 2세대도 동일한 죄를 반복했다는 점입니다. 하나님께서는 그들에게 조상의 악한 길을 따르지 말라고 경고하셨으나, 그들 역시 우상을 따르며 안식일을 더럽혔습니다. 약속의 땅에 들어간 후에는 더욱 심각해져서, 모든 높은 산과 무성한 나무 아래에서 제사를 드리며 심지어 자녀를 불 가운데로 지나게 하는 가증한 일까지 행했습니다.\n\n이제 포로로 잡혀온 상황에서도 그들은 여전히 "우리가 이방인처럼 목석을 경배하리라"라고 말합니다. 그러나 하나님께서는 능한 손과 편 팔로 그들을 다스리시겠다고 선포하십니다. 흩어진 백성을 다시 모으시되, 광야의 심판을 통해 정결케 하신 후에야 약속의 땅으로 인도하시겠다는 것입니다. 이는 심판 속에서도 포기하지 않으시는 하나님의 신실하심을 보여줍니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 반복되는 우상숭배의 역사를 드러내시며, 그럼에도 불구하고 자신의 이름을 위하여 그들을 포기하지 않으시고 능한 손으로 다스리실 것을 약속하십니다.\n\n묵상 질문\n1. 나의 신앙생활에서 반복되는 실패의 패턴은 무엇이며, 그것을 끊기 위해 어떤 결단이 필요할까요?\n2. 하나님께서 자신의 이름을 위하여 인내하신다는 것이 나에게 어떤 위로와 도전이 되나요?\n3. 하나님의 능한 손과 편 팔로 다스리심을 받는다는 것은 무엇을 의미하며, 나는 그 다스림에 순종할 준비가 되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-04', E'심판받는 이스라엘 (에스겔 1장)', E'에스겔 1장', E'포로로 끌려간 지 5년, 그발 강가에서 제사장 에스겔에게 하나님의 영광이 나타났습니다. 북방에서 몰려오는 폭풍과 구름, 번쩍이는 불과 빛은 압도적인 하나님의 임재를 보여주었습니다. 그 가운데 나타난 네 생물의 형상은 각각 사람, 사자, 소, 독수리의 얼굴을 가졌으며, 그들의 날개 아래에는 사람의 손이 있었습니다. 이들은 하나님의 영이 이끄시는 대로 돌이키지 않고 곧게 나아갔으며, 그들 곁의 바퀴들도 함께 움직였습니다. 바퀴 안의 바퀴, 눈으로 가득한 둘레는 하나님의 전지하심과 무소부재하심을 나타냅니다.\n\n생물들의 머리 위에는 수정 같은 궁창이 펼쳐져 있었고, 그 위에는 남보석 같은 보좌가 있었습니다. 보좌 위에는 사람의 모양을 한 형상이 계셨는데, 허리 위아래로 불과 같은 광채가 났습니다. 에스겔이 본 것은 "여호와의 영광의 형상"(겔 1:28)이었습니다. 이는 예루살렘 성전을 떠나신 하나님께서 포로들이 있는 바벨론 땅에서도 여전히 그들과 함께 계심을 보여주는 놀라운 계시였습니다.\n\n이스라엘이 죄로 인해 심판받고 성전이 파괴될 운명에 있었지만, 하나님의 영광은 지역과 장소에 제한받지 않으셨습니다. 오히려 절망의 땅 바벨론에서도 하나님은 당신의 백성과 함께하시며, 새로운 소망의 메시지를 전할 예언자를 부르고 계셨습니다. 에스겔이 엎드려 들은 그 음성은 곧 이스라엘의 회복과 구원을 향한 하나님의 계획이 시작되고 있음을 알리는 신호였습니다.', E'오늘의 핵심\n포로의 땅 바벨론에서도 하나님의 영광은 여전히 임재하시며, 절망 가운데서도 당신의 백성과 함께하시는 하나님의 신실하심이 나타납니다.\n\n묵상 질문\n1. 내 삶의 ''바벨론'', 즉 절망적인 상황에서도 하나님이 함께하심을 경험한 적이 있나요?\n2. 에스겔처럼 하나님의 영광 앞에 엎드려 그분의 음성을 듣고자 하는 마음이 있으신가요?\n3. 하나님의 임재가 장소에 제한받지 않으신다는 사실이 오늘 나에게 어떤 위로와 소망을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-05', E'심판받는 이스라엘 (에스겔 2장)', E'에스겔 2장', E'하나님의 영광을 목격한 에스겔은 얼굴을 땅에 대고 엎드려 있었습니다. 그때 하나님께서는 "인자야 네 발로 일어서라 내가 네게 말하리라"고 명하십니다. 놀랍게도 하나님이 말씀하실 때 그 영이 에스겔에게 임하여 그를 일으켜 세우셨습니다. 이는 하나님의 부르심이 단순히 인간의 의지나 능력에 달린 것이 아니라, 하나님의 영이 함께하실 때 비로소 가능함을 보여줍니다.\n\n하나님께서는 에스겔을 "패역한 백성, 나를 배반하는 자"인 이스라엘 자손에게 보내신다고 말씀하십니다. 그들은 조상 때부터 하나님을 거역해 왔고, 얼굴이 뻔뻔하며 마음이 굳은 상태였습니다. 그런데도 하나님은 포기하지 않으시고 선지자를 보내십니다. 비록 그들이 듣든지 듣지 않든지, 그들 가운데 선지자가 있음을 알게 하시려는 것입니다. 이는 끝까지 기회를 주시는 하나님의 사랑과, 동시에 더 이상 변명할 수 없게 하시는 공의로움을 드러냅니다.\n\n특별히 주목할 것은 하나님께서 에스겔에게 주신 격려의 말씀입니다. "비록 가시와 찔레와 함께 있으며 전갈 가운데에 거주할지라도" 두려워하지 말라고 하십니다. 선지자의 사역이 얼마나 위험하고 고통스러울지를 미리 아시면서도, 하나님은 에스겔이 담대히 말씀을 전하기를 원하셨습니다. \n\n장면은 극적으로 전환되어, 하나님의 손에서 두루마리가 펼쳐집니다. 그 안팎에는 애가와 애곡과 재앙의 말이 가득했습니다. 에스겔은 이 슬픈 메시지를 먹어야 했고, 그것을 백성에게 전해야 했습니다. 심판의 메시지를 전하는 것은 선지자에게도 고통스러운 일이었지만, 이것이 하나님께서 주신 사명이었습니다.', E'오늘의 핵심\n하나님께서는 패역한 백성에게 끝까지 선지자를 보내시어 돌이킬 기회를 주시지만, 동시에 그들이 더 이상 변명할 수 없도록 분명한 심판의 메시지를 전하게 하십니다.\n\n묵상 질문\n1. 하나님의 부르심 앞에 선 에스겔처럼, 나도 하나님의 영으로 일으켜 세움을 받은 경험이 있나요?\n2. 어려운 상황 속에서도 하나님의 말씀을 전해야 할 때, 어떤 두려움이 나를 주저하게 만드나요?\n3. 내가 전해야 할 말씀이 듣기 좋은 것만이 아닐 때, 그것을 어떻게 사랑으로 전할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-06', E'심판받는 이스라엘 (에스겔 3장)', E'에스겔 3장', E'에스겔이 부름받은 선지자의 사명은 결코 쉬운 길이 아니었습니다. 하나님께서는 두루마리를 먹이시며 그 말씀을 온전히 소화하여 전하라고 명하십니다. 놀랍게도 그 두루마리는 "달기가 꿀 같더라"(겔 3:3)고 고백합니다. 심판의 메시지조차도 하나님의 말씀이기에 달콤함을 경험한 것입니다. 이는 예언자가 하나님의 마음과 하나 되어 그 뜻을 온전히 받아들였음을 보여줍니다.\n\n하나님께서는 에스겔을 언어가 통하지 않는 이방 민족이 아닌 이스라엘 백성에게 보내십니다. 그러나 오히려 이방인들이 하나님의 말씀을 더 잘 들었을 것이라는 역설적인 말씀을 하십니다. 동족인 이스라엘 백성은 "이마가 굳고 마음이 굳어" 하나님의 말씀을 거부할 것이라는 예고입니다. 이에 하나님께서는 에스겔의 이마를 금강석같이 단단하게 하시어 반역하는 백성들 앞에서도 굴하지 않고 사명을 감당할 수 있도록 준비시키십니다.\n\n특별히 하나님께서는 에스겔을 "파수꾼"으로 세우십니다. 파수꾼은 위험을 미리 알려 백성을 보호하는 중대한 책임을 지닌 자입니다. 악인에게 경고하지 않으면 그 피값을 파수꾼에게서 찾겠다는 엄중한 말씀은 영혼을 향한 하나님의 간절한 마음을 보여줍니다. 의인이 타락할 때도 마찬가지로 경고해야 할 책임이 있습니다. 이는 구원받은 자도 계속해서 하나님의 말씀으로 깨어있어야 함을 가르칩니다.\n\n그발 강가에서 하나님의 영광을 다시 목격한 에스겔은 엎드릴 수밖에 없었습니다. 그러나 주의 영이 그를 일으켜 세우십니다. 이는 하나님의 능력으로만 그 사명을 감당할 수 있음을 보여주는 장면입니다. 비록 백성들이 그를 결박하고 그의 혀가 입천장에 붙어 잠시 침묵하게 될지라도, 하나님께서 말씀하실 때 그 입은 열릴 것입니다. 패역한 백성 가운데서도 하나님의 때에 하나님의 방법으로 말씀은 선포될 것입니다.', E'오늘의 핵심\n하나님께서는 에스겔을 이스라엘의 파수꾼으로 세우시며, 듣기를 거부하는 완악한 백성에게도 끝까지 경고의 메시지를 전하도록 하십니다.\n\n묵상 질문\n1. 하나님의 말씀이 내게는 꿀처럼 달콤하게 느껴지나요, 아니면 부담스럽게 느껴지나요?\n2. 내가 누군가의 영적 파수꾼 역할을 해야 할 사람은 누구인가요?\n3. 말씀을 전하기 어려운 상황에서도 하나님의 능력을 의지한 경험이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-08', E'심판받는 이스라엘 (에스겔 4장)', E'에스겔 4장', E'하나님께서는 에스겔에게 독특한 상징적 행동을 명령하십니다. 토판에 예루살렘 성을 그리고, 그 주위에 포위 공격의 모습을 재현하라고 하십니다. 사다리와 흙언덕, 진영과 공성퇴를 설치하고, 철판으로 철벽을 만들어 놓으라는 것입니다. 이 생생한 모형은 곧 닥쳐올 예루살렘의 운명을 미리 보여주는 징조였습니다.\n\n더욱 놀라운 것은 에스겔이 직접 몸으로 표현해야 할 내용입니다. 왼쪽으로 390일간 누워 북이스라엘의 죄를, 오른쪽으로 40일간 누워 남유다의 죄를 담당하라고 하십니다. 하루가 일 년을 상징하는 이 기간은 각각 이스라엘과 유다가 하나님을 떠나 있던 세월을 나타냅니다. 하나님께서는 줄로 에스겔을 묶어 그가 몸을 돌릴 수도 없게 하심으로써, 심판의 확정성과 불가피성을 보여주십니다.\n\n포위된 성에서 겪을 기근의 참상도 미리 체험하게 하십니다. 하루에 약 230그램의 혼합 곡물 떡과 0.6리터의 물만으로 연명하는 것은 극심한 식량 부족 상황을 나타냅니다. 특히 인분으로 불을 피워 떡을 굽는 것은 이방 땅에서 겪을 부정함과 수치를 상징합니다. 에스겔이 이를 거부하자 하나님께서 쇠똥으로 대체하도록 허락하신 것은, 선지자의 정결함을 배려하시면서도 메시지의 본질은 타협하지 않으시는 하나님의 성품을 보여줍니다.\n\n"내가 예루살렘에서 의뢰하는 양식을 끊으리니"(겔 4:16)라는 하나님의 선언은 단순한 물리적 기근이 아닙니다. 하나님을 떠나 우상과 권력을 의지했던 예루살렘이 마침내 그 모든 의지처를 잃고 절망 가운데 빠질 것을 예고합니다. 에스겔의 상징적 행동은 이 모든 심판의 메시지를 백성들의 눈앞에 생생하게 펼쳐 보이는 하나님의 마지막 경고였습니다.', E'오늘의 핵심\n하나님께서는 에스겔의 몸을 통한 상징적 행동으로 예루살렘에 임할 포위와 기근, 그리고 포로 생활의 비참함을 미리 보여주시며 회개를 촉구하십니다.\n\n묵상 질문\n1. 하나님께서 이토록 구체적이고 충격적인 방법으로 경고하시는 이유는 무엇일까요?\n2. 내 삶에서 하나님보다 더 의지하고 있는 ''양식''은 무엇인가요?\n3. 오늘 하나님께서 내게 보여주시는 경고의 징조를 무시하고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-09', E'심판받는 이스라엘 (에스겔 5장)', E'에스겔 5장', E'에스겔은 하나님의 명령에 따라 매우 충격적인 상징 행동을 수행하게 됩니다. 날카로운 칼로 자신의 머리털과 수염을 깎아 저울로 달아 삼등분하는 모습은, 예루살렘에 임할 심판의 구체적인 모습을 보여주고 있습니다. 고대 근동에서 머리털과 수염은 한 사람의 정체성과 명예를 상징했기에, 이를 깎는다는 것은 철저한 수치와 파괴를 의미했습니다.\n\n삼분의 일은 성읍 안에서 불사르고, 삼분의 일은 칼로 치고, 나머지 삼분의 일은 바람에 흩어버리는 에스겔의 행동은 예루살렘 백성들이 당할 운명을 생생하게 보여줍니다. 전염병과 기근으로 죽는 자, 칼에 죽는 자, 그리고 사방으로 흩어질 자들의 모습이 예언자의 상징적 행동을 통해 미리 계시되고 있는 것입니다. 옷자락에 싸두었던 소량의 머리털마저 다시 불에 태우는 모습은 남은 자들조차 온전하지 못할 것임을 암시합니다.\n\n하나님께서는 예루살렘을 "이방인 가운데에 두어 나라들이 둘러 있게 하였거늘"(겔 5:5)이라고 말씀하십니다. 이는 예루살렘이 열방의 중심에서 하나님의 영광을 드러내는 특권적 위치에 있었음을 보여줍니다. 그러나 그들은 오히려 주변 이방 민족들보다 더 악을 행하며 하나님의 규례를 버렸습니다. 특별한 은혜를 받은 만큼 그들의 책임도 컸지만, 그들은 그 책임을 저버렸습니다.\n\n가장 충격적인 것은 "아버지가 아들을 잡아먹고 아들이 그 아버지를 잡아먹으리라"는 예언입니다. 이는 극도의 기근 상황에서 일어날 끔찍한 일을 암시하는데, 실제로 예루살렘 포위 때 이런 참상이 일어났다고 역사는 기록하고 있습니다. 하나님의 성소를 우상으로 더럽힌 결과가 얼마나 처참한지를 보여주는 대목입니다.\n\n이 모든 심판의 목적은 단순한 보복이 아니었습니다. "나 여호와가 열심으로 말한 줄을 그들이 알리라"는 말씀처럼, 하나님께서는 당신이 살아계신 참 하나님이심을 깨닫게 하려는 것이었습니다. 심판을 통해서라도 하나님의 거룩하심과 공의로우심을 드러내시는 하나님의 뜻이 담겨 있습니다.', E'오늘의 핵심\n하나님께서는 에스겔의 충격적인 상징 행동을 통해 예루살렘에 임할 심판의 구체적인 모습을 보여주시며, 특권을 받은 백성이 더 큰 책임을 져야 함을 일깨워 주십니다.\n\n묵상 질문\n1. 하나님께서 주신 특별한 은혜와 위치를 나는 어떻게 사용하고 있나요?\n2. 내 삶에서 하나님보다 더 중요하게 여기는 우상은 무엇인가요?\n3. 하나님의 경고를 듣고도 무시했던 경험이 있다면 어떤 것이었나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-10', E'심판받는 이스라엘 (에스겔 6장)', E'에스겔 6장', E'여호와의 말씀이 에스겔에게 임하여 이스라엘 산들을 향한 심판의 메시지를 전하게 하십니다. 하나님께서는 산과 언덕, 시내와 골짜기에 이르기까지 이스라엘 전 땅에 칼이 임할 것을 선포하십니다. 이 심판의 핵심은 우상숭배의 중심지인 산당들을 완전히 멸하시겠다는 것입니다. 제단들은 황폐하게 되고, 분향제단들은 깨어지며, 우상을 섬기던 자들의 시체가 바로 그 우상들 앞에 엎드러지게 될 것이라고 하나님은 말씀하십니다.\n\n이스라엘이 받게 될 심판의 모습은 참혹합니다. 먼 곳에 있는 자는 전염병으로, 가까운 곳에 있는 자는 칼에 죽임을 당하고, 살아남아 포위된 자들은 기근으로 죽게 될 것입니다. 그들이 우상에게 분향하던 모든 장소 - 높은 고개, 산꼭대기, 푸른 나무와 상수리나무 아래 - 에 시체가 널려있게 될 것입니다. 하나님께서는 이러한 철저한 심판을 통해 "내가 여호와인 줄을 너희가 알게 하려 함이라"고 그 목적을 분명히 밝히십니다.\n\n그러나 하나님의 심판 가운데서도 은혜의 빛줄기가 보입니다. 하나님께서는 "칼을 피하여 이방인들 중에 살아 남은 자가 있게 할지라"고 말씀하십니다. 포로로 끌려간 이들이 이방 땅에서 비로소 자신들의 죄를 깨닫고 회개하게 될 것입니다. 그들은 음란한 마음으로 하나님을 떠나 우상을 섬겼던 일을 기억하고 스스로 한탄하게 됩니다. 심판의 목적이 단순한 멸망이 아니라, 하나님을 알고 돌아오게 하는 것임을 보여줍니다. 광야에서부터 디블라까지 온 땅이 황폐하게 되는 심판을 통해서라도, 하나님께서는 당신의 백성이 여호와 하나님을 알기를 원하십니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 우상숭배에 대한 철저한 심판을 선포하시면서도, 남은 자들이 회개하고 돌아올 수 있는 은혜의 길을 열어두십니다.\n\n묵상 질문\n1. 나의 삶에서 하나님보다 더 의지하고 있는 ''현대의 우상''은 무엇인가요?\n2. 하나님의 징계를 통해 깨달았던 경험이 있다면 무엇이었나요?\n3. 심판 중에도 은혜를 베푸시는 하나님의 마음을 어떻게 이해하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-11', E'심판받는 이스라엘 (에스겔 7장)', E'에스겔 7장', E'여호와의 말씀이 에스겔에게 임하여 이스라엘 땅에 대한 최후의 심판을 선포합니다. "끝났도다 이 땅 사방의 일이 끝났도다"라는 하나님의 선언은 더 이상의 유예나 기회가 없음을 분명히 보여줍니다. 반복적으로 울려 퍼지는 ''끝''이라는 단어는 심판의 확정성과 급박성을 강조하며, 이스라엘이 맞이할 운명의 무게를 전달합니다.\n\n하나님께서는 이스라엘의 죄악에 대해 더 이상 불쌍히 여기지도, 긍휼히 여기지도 않으시겠다고 선언하십니다. 그들이 화려한 장식으로 교만을 품고 금과 은으로 우상을 만들어 섬긴 죄악이 이제 그들에게 보응으로 돌아옵니다. 특히 주목할 것은 그들이 의지하던 재물이 심판의 날에는 아무런 도움이 되지 못한다는 사실입니다. 오히려 그 금과 은이 "죄악의 걸림돌"이 되어 거리에 던져질 오물처럼 취급받게 됩니다.\n\n심판의 도구로 사용되는 것은 극악한 이방인들입니다. 하나님께서는 바벨론을 통해 이스라엘을 치시며, 성소마저 더럽혀지도록 허락하십니다. 전쟁의 나팔이 울려도 싸울 사람이 없고, 선지자에게 묵시를 구해도 헛되며, 제사장에게는 율법이, 장로에게는 지혜가 사라집니다. 이는 하나님과의 관계가 단절될 때 나타나는 영적 공백과 혼란의 극치를 보여줍니다.\n\n그러나 이 엄중한 심판의 메시지 속에서도 하나님의 궁극적인 목적은 분명합니다. "내가 여호와인 줄을 너희가 알리라"는 말씀이 반복되는 것은, 심판을 통해서라도 하나님께서 자신이 누구신지를 알게 하시려는 하나님의 뜻을 드러냅니다. 죄악으로 어두워진 백성의 영적 눈을 여시고자 하는 하나님의 아픈 사랑이 엄중한 심판의 메시지 뒤에 숨어 있습니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 끝없는 죄악에 대해 최후의 심판을 선포하시며, 그들이 의지하던 모든 것이 무너질 때 비로소 여호와 하나님이 누구신지 알게 될 것임을 말씀하십니다.\n\n묵상 질문\n1. 내가 하나님보다 더 의지하고 있는 ''금과 은''은 무엇인가요?\n2. 반복되는 하나님의 경고를 무시하고 있는 나의 모습은 없나요?\n3. 하나님께서 "내가 여호와인 줄 알리라"고 하신 말씀이 오늘 내게 어떤 의미로 다가오나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-12', E'심판받는 이스라엘 (에스겔 8장)', E'에스겔 8장', E'바벨론 포로로 끌려간 지 6년째 되던 해, 에스겔은 집에서 유다의 장로들과 함께 있을 때 하나님의 권능이 임하는 경험을 합니다. 하나님께서는 환상 중에 에스겔을 예루살렘 성전으로 데려가셔서 그곳에서 벌어지고 있는 충격적인 장면들을 보여주십니다. 이 환상은 단순한 계시가 아니라, 예루살렘 멸망이 임박했음을 알리는 하나님의 마지막 경고였습니다.\n\n에스겔이 목격한 첫 번째 장면은 성전 북문 입구에 세워진 ''질투의 우상''이었습니다. 하나님의 거룩한 임재가 머물러야 할 성전에 우상이 버젓이 자리 잡고 있었던 것입니다. 그러나 이것은 시작에 불과했습니다. 하나님께서는 에스겔을 더 깊은 곳으로 인도하시며 은밀히 행해지는 더욱 가증한 일들을 보여주십니다.\n\n성전 안 밀실에서는 이스라엘의 장로 70명이 벽에 그려진 각종 우상들 앞에서 분향하고 있었습니다. 그들은 "여호와께서 우리를 보지 아니하시며 여호와께서 이 땅을 버리셨다"(겔 8:12)고 말하며 자신들의 행위를 정당화했습니다. 성전 북문에서는 여인들이 바벨론의 풍요의 신 담무스를 위해 애곡하고 있었고, 성전 안뜰에서는 제사장들이 하나님의 성전을 등지고 동쪽 태양을 향해 절하고 있었습니다.\n\n이 모든 장면은 이스라엘의 영적 타락이 얼마나 심각한 지경에 이르렀는지를 보여줍니다. 그들은 하나님의 임재를 믿지 않았고, 오히려 하나님께서 그들을 버리셨다고 생각했습니다. 이러한 불신앙은 곧 우상숭배로 이어졌고, 성전은 각종 가증한 일들로 더럽혀졌습니다. 하나님께서는 이러한 백성들의 모습에 진노하시며, 그들의 부르짖음을 듣지 않겠다고 선포하십니다.\n\n에스겔이 본 이 환상은 곧 현실이 되었습니다. 예루살렘은 바벨론에 의해 완전히 파괴되었고, 성전은 불타 없어졌습니다. 그러나 이 심판의 메시지 속에서도 우리는 하나님의 마음을 읽을 수 있습니다. 하나님께서는 끝까지 당신의 백성이 돌아오기를 기다리셨고, 환상을 통해서라도 그들에게 경고의 메시지를 전하고자 하셨던 것입니다.', E'오늘의 핵심\n하나님께서는 에스겔에게 예루살렘 성전에서 은밀히 행해지는 우상숭배의 실상을 보여주시며, 영적 타락이 극에 달한 이스라엘에 대한 심판이 임박했음을 선포하십니다.\n\n묵상 질문\n1. 나는 하나님께서 보고 계시지 않다고 생각하며 은밀히 행하는 일이 있나요?\n2. 내 마음의 성전에 하나님 대신 자리 잡고 있는 우상은 무엇인가요?\n3. 하나님의 경고의 음성을 외면하고 있는 내 삶의 영역은 어디일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-13', E'심판받는 이스라엘 (에스겔 9장)', E'에스겔 9장', E'에스겔이 환상 가운데 보게 된 것은 예루살렘에 임할 하나님의 심판이었습니다. 여섯 명의 심판 집행자들이 각자 죽이는 무기를 손에 들고 북쪽 문으로부터 들어오는 모습은 곧 바벨론 군대가 북쪽에서 침략해 올 것을 암시합니다. 그런데 그들 중에 한 사람은 가는 베옷을 입고 서기관의 먹 그릇을 찬 독특한 모습으로 나타납니다. \n\n하나님께서는 이 서기관에게 먼저 예루살렘 성읍을 순행하며 "그 가운데에서 행하는 모든 가증한 일로 말미암아 탄식하며 우는 자의 이마에 표를 그리라"(겔 9:4)고 명령하십니다. 이 표는 구원의 표시였습니다. 우상숭배와 불의가 만연한 예루살렘에서도 여전히 하나님의 마음에 합한 사람들, 죄악을 보며 탄식하고 애통해하는 신실한 남은 자들이 있었던 것입니다. \n\n심판은 철저했습니다. 늙은 자와 젊은 자, 처녀와 어린이, 여자까지 모두 죽이되 오직 이마에 표가 있는 자만은 건드리지 말라는 명령이 내려집니다. 더욱 충격적인 것은 이 심판이 하나님의 성소, 곧 성전에서부터 시작된다는 점입니다. 성전 앞의 장로들부터 심판을 받기 시작했습니다. 종교 지도자들이 먼저 심판받는 것은 그들에게 더 큰 책임이 있었기 때문입니다.\n\n에스겔은 이 참혹한 광경을 보며 엎드려 부르짖습니다. 그러나 하나님의 대답은 단호했습니다. 이스라엘과 유다의 죄악이 너무나 심각하여 땅에는 피가 가득하고 성읍에는 불법이 가득했습니다. 무엇보다 그들은 "여호와께서 이 땅을 버리셨으며 여호와께서 보지 아니하신다"고 말하며 하나님의 존재와 심판을 부인했습니다. \n\n이 환상은 우리에게 하나님의 공의로운 심판과 함께 그분의 세심한 구원을 보여줍니다. 심판 가운데서도 신실한 남은 자를 구별하시는 하나님의 은혜가 빛나고 있습니다.', E'오늘의 핵심\n하나님께서는 예루살렘의 철저한 심판을 명하시면서도, 죄악을 보며 탄식하는 신실한 남은 자들을 표시하여 구원하시는 세심한 은혜를 보여주십니다.\n\n묵상 질문\n1. 죄악이 만연한 시대에 탄식하며 우는 자가 된다는 것은 어떤 의미일까요?\n2. 심판이 하나님의 성소에서부터 시작된다는 사실이 오늘날 교회에 주는 경고는 무엇일까요?\n3. 나는 하나님께서 이 땅을 보고 계시다는 확신을 가지고 살아가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-15', E'심판받는 이스라엘 (에스겔 10장)', E'에스겔 10장', E'에스겔이 목격한 환상은 이스라엘 역사상 가장 비극적인 순간을 보여주고 있습니다. 여호와의 영광이 성전을 떠나는 장면은 단순한 상징이 아니라, 하나님께서 자기 백성과 함께하시던 언약의 관계가 파기되는 충격적인 현실을 드러냅니다. 가는 베 옷을 입은 사람에게 그룹들 사이에서 숯불을 가져다가 예루살렘 성읍 위에 흩으라는 명령은 심판의 불이 곧 임할 것임을 예고합니다. 이 숯불은 거룩한 제단에서 나온 것이지만, 이제는 심판의 도구가 되어 죄악으로 가득한 도성을 정결케 하는 역할을 하게 됩니다.\n\n여호와의 영광이 성전 문지방을 떠나 그룹들 위에 머무르고, 결국 동문으로 이동하는 과정은 하나님의 임재가 단계적으로 성전을 떠나가는 모습을 보여줍니다. 이는 하나님께서 갑작스럽게 떠나신 것이 아니라, 오랜 인내 끝에 마지못해 떠나시는 것임을 암시합니다. 그룹들과 바퀴의 일체된 움직임은 하나님의 주권적인 통치가 여전히 계속되고 있음을 보여주며, 비록 예루살렘을 떠나시지만 하나님께서는 여전히 역사의 주관자이심을 선포합니다.\n\n에스겔이 그발 강가에서 보았던 그 생물들이 바로 그룹임을 깨닫는 순간은 하나님의 영광이 이미 포로 된 백성들 가운데 함께하셨음을 확인시켜 줍니다. 성전을 떠나는 하나님의 영광이 바벨론 포로들에게로 향한다는 것은 심판 가운데서도 남은 자들을 통한 구원의 희망이 있음을 보여주는 은혜의 메시지입니다.', E'오늘의 핵심\n여호와의 영광이 성전을 떠나는 충격적인 환상은 이스라엘의 죄악에 대한 최종적인 심판을 선포하면서도, 동시에 포로 된 백성들과 함께하시는 하나님의 신실하심을 보여줍니다.\n\n묵상 질문\n1. 하나님의 임재가 떠난다는 것이 우리에게 주는 영적 경고는 무엇일까요?\n2. 심판 중에도 은혜를 베푸시는 하나님의 성품을 어떻게 이해할 수 있을까요?\n3. 오늘 나의 삶에서 하나님의 영광이 머물 수 있는 거룩한 공간은 어디인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-16', E'심판받는 이스라엘 (에스겔 11장)', E'에스겔 11장', E'에스겔은 하나님의 영에 이끌려 예루살렘 성전 동문에서 스물다섯 명의 지도자들을 봅니다. 그중 야아사냐와 블라댜는 백성의 고관으로서 마땅히 하나님의 뜻을 따라 백성을 이끌어야 했지만, 오히려 악한 계획을 꾸미고 있었습니다. 그들은 "이 성읍은 가마가 되고 우리는 고기가 된다"라고 말하며 자신들이 안전하다고 착각했습니다. 가마 속의 고기가 불에 타지 않듯이 예루살렘이 자신들을 보호해 줄 것이라는 거짓된 안도감에 빠져 있었던 것입니다.\n\n하나님께서는 이러한 거짓 지도자들의 죄악을 낱낱이 드러내십니다. 그들은 무고한 사람들을 죽여 거리를 시체로 채웠고, 하나님의 율례를 버리고 이방인의 규례를 따랐습니다. 에스겔이 예언하던 중 블라댜가 죽자, 예언자는 큰 소리로 부르짖으며 이스라엘의 남은 자마저 멸절되는 것이 아닌지 두려워합니다. 이는 심판의 엄중함과 함께 하나님의 백성을 향한 애타는 마음을 보여줍니다.\n\n그러나 하나님의 계획은 단순한 멸망에 그치지 않습니다. 비록 백성들을 여러 나라에 흩으셨지만, 그곳에서 잠깐이나마 그들에게 성소가 되어주시겠다고 약속하십니다. 더 나아가 흩어진 백성들을 다시 모으시고 이스라엘 땅으로 돌아오게 하실 것이며, 무엇보다 그들에게 "새 마음과 새 영"을 주시겠다고 선포하십니다. 돌같이 굳은 마음을 제거하고 살처럼 부드러운 마음을 주셔서, 하나님의 율례를 따르는 참된 백성이 되게 하시겠다는 것입니다.\n\n에스겔이 본 환상의 마지막에 여호와의 영광이 성전을 떠나 동쪽 산으로 이동하는 장면은 깊은 의미를 담고 있습니다. 하나님께서 불순종하는 백성과 더럽혀진 성전을 떠나시는 것은 심판의 시작을 알리는 동시에, 동쪽 산에 머무르시는 모습은 완전한 단절이 아닌 회복의 여지를 남겨두신 것입니다. 이는 심판 속에서도 자비를 잃지 않으시는 하나님의 성품을 보여줍니다.', E'오늘의 핵심\n하나님께서는 거짓 지도자들의 죄악을 심판하시면서도, 흩어진 백성들에게 새 마음과 새 영을 주셔서 참된 하나님의 백성으로 회복시키실 것을 약속하십니다.\n\n묵상 질문\n1. 내가 의지하고 있는 거짓된 안전감은 무엇이며, 참된 피난처는 어디에서 찾을 수 있을까요?\n2. 하나님께서 내게 주시고자 하시는 ''새 마음''은 어떤 모습일까요?\n3. 심판 가운데서도 회복을 약속하시는 하나님의 마음을 어떻게 이해하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-17', E'심판받는 이스라엘 (에스겔 12장)', E'에스겔 12장', E'바벨론에 포로로 끌려간 지 수년이 지났지만, 포로 공동체는 여전히 예루살렘이 곧 회복되리라는 헛된 희망에 사로잡혀 있었습니다. 하나님께서는 에스겔에게 특별한 상징 행동을 명하십니다. 포로의 행장을 꾸려 어깨에 메고, 성벽을 뚫고 나가는 모습을 백성들 앞에서 행하라는 것이었습니다. 이 충격적인 행동은 곧 닥칠 예루살렘의 운명을 미리 보여주는 예언이었습니다. 특히 시드기야 왕이 밤중에 몰래 도망치다가 붙잡혀 눈이 뽑힌 채 바벨론으로 끌려갈 것까지 구체적으로 예언되었습니다.\n\n하나님께서는 "반역하는 족속"이라는 표현을 반복하시며 이스라엘의 영적 상태를 진단하십니다. 그들에게는 볼 눈이 있어도 보지 못하고, 들을 귀가 있어도 듣지 못하는 영적 둔감함이 있었습니다. 포로들 사이에는 "날이 더디고 모든 묵시가 사라지리라"는 속담이 유행했는데, 이는 에스겔의 예언을 조롱하며 하나님의 심판이 결코 오지 않을 것이라 믿는 그들의 완악함을 보여줍니다. 그러나 하나님께서는 분명히 선포하십니다. 더 이상 지체되지 않을 것이며, 말씀하신 그대로 이루어질 것이라고 말입니다.\n\n하나님의 심판 가운데서도 은혜는 계속됩니다. 칼과 기근과 전염병에서 살아남은 소수의 사람들이 이방인들 가운데서 자신들의 가증한 일을 자백하게 될 것입니다. 이는 단순한 생존이 아니라 회개와 증언의 도구로 남겨지는 것입니다. 하나님께서는 끝까지 당신이 여호와이심을 알게 하시려는 목적을 포기하지 않으십니다. 심판의 엄중함 속에서도 구원의 소망을 품고 계시는 하나님의 마음이 에스겔의 상징적 행동을 통해 절절히 전달됩니다.', E'오늘의 핵심\n하나님께서는 에스겔의 상징적 행동을 통해 예루살렘의 임박한 멸망을 생생하게 보여주시며, 반역하는 백성들에게 마지막 경고의 기회를 주십니다.\n\n묵상 질문\n1. 영적으로 둔감해진 나의 모습은 없는지, 하나님의 음성에 귀 기울이고 있나요?\n2. 하나님의 경고를 가볍게 여기며 "아직 시간이 있다"고 미루고 있는 일은 무엇인가요?\n3. 심판 중에도 은혜를 베푸시는 하나님께 오늘 어떤 응답으로 나아가야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-18', E'심판받는 이스라엘 (에스겔 13장)', E'에스겔 13장', E'하나님의 참된 말씀이 절실히 필요한 때에 거짓 선지자들이 백성을 미혹하고 있었습니다. 에스겔을 통해 하나님께서는 이들의 실체를 낱낱이 폭로하시며 엄중한 심판을 선포하십니다. 거짓 선지자들은 하나님께서 보이지 않으신 것을 보았다 하고, 말씀하지 않으신 것을 전했습니다. "본 것이 없이 자기 심령을 따라 예언하는 어리석은 선지자"(겔 13:3)라는 표현은 그들의 본질을 정확히 드러냅니다. 그들은 황무지의 여우처럼 파괴된 성벽의 틈을 이용할 뿐, 진정으로 백성을 위해 무너진 곳을 수축하지 않았습니다.\n\n특히 심각한 것은 그들이 평강이 없는데도 평강을 선포했다는 점입니다. 백성들이 죄악 가운데 있으면서도 회개할 필요가 없다고 안심시켰던 것입니다. 하나님께서는 이를 부실한 담에 회칠하는 것에 비유하십니다. 겉으로는 번듯해 보이지만 폭풍우가 몰아치면 결국 무너질 수밖에 없는 담입니다. 거짓 선지자들의 메시지도 마찬가지였습니다. 당장은 듣기 좋았지만 하나님의 심판 앞에서는 아무런 보호막이 되지 못했습니다.\n\n여선지자들의 죄악도 만만치 않았습니다. 그들은 부적과 수건으로 사람들의 영혼을 사냥했습니다. 보리 몇 움큼과 떡 조각을 받고 거짓 예언을 하며, 죽지 않을 자를 죽인다 하고 살지 못할 자를 살린다고 속였습니다. 하나님께서는 이러한 모든 거짓을 끝내시고 당신의 백성을 그들의 손에서 건져내시겠다고 약속하십니다. 참된 하나님의 말씀만이 백성을 구원으로 인도할 수 있기 때문입니다.', E'오늘의 핵심\n거짓 선지자들은 하나님의 이름을 빌려 자기 마음대로 예언하며 백성을 미혹했지만, 하나님께서는 그들의 거짓을 폭로하시고 당신의 백성을 건져내십니다.\n\n묵상 질문\n1. 오늘날에도 평안이 없는데 평안을 외치는 거짓된 메시지들이 있지 않을까요?\n2. 하나님의 참된 음성과 거짓 음성을 구별하는 나만의 기준은 무엇인가요?\n3. 내가 듣기 좋은 말에만 귀를 기울이고 있지는 않은지 돌아볼 때입니다. 오늘 하나님께서 내게 주시는 불편하지만 참된 말씀은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-19', E'심판받는 이스라엘 (에스겔 14장)', E'에스겔 14장', E'포로로 끌려온 이스라엘 장로들이 에스겔을 찾아와 하나님의 뜻을 묻고자 합니다. 그러나 하나님께서는 그들의 마음속 깊이 자리 잡은 우상숭배의 실상을 폭로하십니다. 겉으로는 여호와 하나님을 찾는 것처럼 보이지만, 실제로는 마음에 우상을 품고 죄악의 걸림돌을 앞에 둔 채로 선지자에게 나아온 것입니다. 하나님께서는 이러한 이중적 태도를 가진 자들에게 "그 우상의 수효대로 보응하리니"(겔 14:4)라고 선포하십니다. 이는 각자가 섬기는 우상의 성격과 방식대로 심판받게 될 것이라는 엄중한 경고입니다.\n\n하나님의 궁극적인 목적은 심판 자체가 아니라 회복입니다. 백성들이 마음을 돌이켜 우상을 떠나고, 다시는 미혹되어 하나님을 떠나지 않게 하시려는 것입니다. 그래서 하나님께서는 "그들을 내 백성으로 삼고 나는 그들의 하나님이 되려 함이라"라고 말씀하십니다. 이는 깨어진 언약 관계를 회복하시려는 하나님의 간절한 소망을 보여줍니다.\n\n그러나 불법을 행하며 하나님께 범죄하는 나라에는 피할 수 없는 심판이 임합니다. 하나님께서는 네 가지 중한 벌 - 칼, 기근, 사나운 짐승, 전염병 - 을 말씀하시면서, 설령 노아, 다니엘, 욥과 같은 의인이 있다 할지라도 그들의 의로움으로는 자기 생명만 건질 뿐 자녀나 다른 사람을 구원할 수 없다고 단언하십니다. 이는 각 사람이 자신의 신앙과 행위에 대해 개인적으로 책임져야 함을 가르쳐줍니다.\n\n그럼에도 불구하고 하나님께서는 심판 중에도 은혜의 여지를 남겨두십니다. 예루살렘에서 끌려 나올 남은 자들을 통해 포로된 백성들이 위로를 받게 될 것이라고 말씀하십니다. 이들의 행동과 소행을 보면서 하나님의 심판이 결코 이유 없이 행해진 것이 아님을 깨닫게 될 것입니다. 이처럼 하나님의 심판 속에는 언제나 교훈과 회복의 소망이 담겨 있습니다.', E'오늘의 핵심\n마음에 우상을 품은 채로는 하나님께 나아갈 수 없으며, 각 사람은 자신의 신앙에 대해 개인적으로 책임져야 합니다. 하나님의 심판은 공의로우나 그 목적은 언제나 회복에 있습니다.\n\n묵상 질문\n1. 내 마음속에 하나님보다 더 의지하고 있는 우상은 무엇인가요?\n2. 하나님께서 "그들을 내 백성으로 삼고 나는 그들의 하나님이 되려 함이라"고 하신 말씀이 나에게 어떤 위로와 도전을 주나요?\n3. 다른 사람의 신앙에 의존하지 않고 나 자신이 하나님 앞에 바로 서기 위해 오늘 무엇을 결단해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-20', E'심판받는 이스라엘 (에스겔 15장)', E'에스겔 15장', E'에스겔 선지자에게 주신 하나님의 말씀은 예루살렘과 유다 백성을 향한 엄중한 심판의 메시지를 담고 있습니다. 하나님께서는 포도나무의 비유를 통해 이스라엘의 현재 상태를 적나라하게 드러내십니다. 포도나무는 원래 열매를 맺어 사람들에게 기쁨을 주는 나무입니다. 그러나 열매를 맺지 못하는 포도나무는 다른 나무들과 달리 목재로서의 가치도 없습니다. 건축 자재로 쓸 수도 없고, 심지어 물건을 걸 못조차 만들 수 없는 쓸모없는 나무가 되어버립니다.\n\n하나님께서는 이스라엘을 택하여 거룩한 백성으로 삼으시고 열방 가운데서 하나님의 영광을 드러내는 열매를 맺기를 기대하셨습니다. 그러나 이스라엘은 그 부르심에 합당한 삶을 살지 못했고, 오히려 우상을 숭배하며 하나님을 배반했습니다. "내가 수풀 가운데에 있는 포도나무를 불에 던질 땔감이 되게 한 것 같이 내가 예루살렘 주민도 그같이 할지라"(겔 15:6)는 말씀은 하나님의 심판이 얼마나 철저할 것인지를 보여줍니다.\n\n특히 주목할 점은 하나님께서 "그들이 그 불에서 나와도 불이 그들을 사르리니"라고 말씀하신 부분입니다. 이는 한 번의 심판으로 끝나지 않고 계속되는 심판을 의미합니다. 바벨론의 1차 포로기를 겪고도 회개하지 않는다면 더 큰 심판이 임할 것임을 경고하고 있습니다. 하나님께서는 이러한 심판을 통해 "내가 여호와인 줄 너희가 알리라"고 말씀하십니다. 심판의 목적이 단순한 형벌이 아니라 하나님을 바로 알고 돌아오게 하려는 사랑의 표현임을 깨닫게 됩니다.\n\n오늘날 우리도 하나님의 포도나무로 부름받았습니다. 우리가 맺어야 할 열매는 무엇인지, 혹시 쓸모없는 땔감이 되어가고 있지는 않은지 돌아보아야 합니다. 하나님의 은혜로 구원받은 우리가 그 은혜에 합당한 열매를 맺으며 살아가는 것이 진정한 감사의 표현입니다.', E'오늘의 핵심\n하나님께서는 열매 맺지 못하는 포도나무의 비유를 통해 이스라엘의 무용함과 다가올 심판을 선포하시며, 그들이 본래의 사명을 잃어버렸음을 지적하십니다.\n\n묵상 질문\n1. 하나님께서 나에게 기대하시는 열매는 무엇이며, 나는 그 열매를 맺고 있나요?\n2. 혹시 내가 하나님의 은혜를 당연하게 여기며 살고 있지는 않나요?\n3. 오늘 나의 삶이 하나님께 기쁨이 되는 포도나무인지, 아니면 땔감에 불과한지 점검해보면 어떨까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-22', E'심판받는 이스라엘 (에스겔 16장)', E'에스겔 16장', E'가나안 땅에서 태어났지만 아무도 돌보지 않아 피투성이로 버려진 갓난아기였던 예루살렘을 하나님께서 발견하시고 살려주셨습니다. 에스겔은 이러한 비유를 통해 예루살렘의 기원과 하나님의 은혜를 생생하게 전달합니다. 하나님은 버려진 이 아기를 단순히 살려주신 것이 아니라, 극진히 돌보시어 아름다운 여인으로 성장시키셨고, 언약의 관계로 맺어주셨습니다. 금과 은으로 장식하시고, 고운 베와 수놓은 옷을 입히시며, 왕후의 지위에까지 오르게 하신 것은 오직 하나님의 일방적인 사랑과 은혜였습니다.\n\n그러나 예루살렘은 하나님께서 주신 아름다움과 명성을 가지고 행음하기 시작했습니다. 하나님께서 주신 금은 장식품으로 우상을 만들고, 하나님의 기름과 향을 우상 앞에 바쳤으며, 심지어 자녀들을 우상에게 제물로 바쳤습니다. 애굽, 앗수르, 바벨론 등 주변 강대국들과 정치적 동맹을 맺으면서 그들의 우상숭배 문화까지 받아들인 예루살렘의 모습은 남편을 배신하고 다른 남자들과 간음하는 아내로 묘사됩니다. 더욱 충격적인 것은 일반 창기와 달리 오히려 값을 주면서까지 우상을 섬겼다는 점입니다.\n\n이제 하나님께서는 예루살렘의 행위에 대한 심판을 선언하십니다. 그들이 의지했던 열방이 오히려 그들을 심판하는 도구가 될 것이며, 그들의 수치가 만천하에 드러날 것입니다. 그러나 이 무서운 심판의 선언 가운데서도 하나님의 마음은 분노보다는 배신당한 사랑의 아픔으로 가득 차 있음을 볼 수 있습니다. "네가 어렸을 때에 벌거벗은 몸이었으며 피투성이가 되어서 발짓하던 것을 기억하지 아니하고"라는 하나님의 탄식은 은혜를 잊어버린 백성을 향한 안타까움을 담고 있습니다.', E'오늘의 핵심\n하나님께서는 버려진 예루살렘을 구원하시고 영화롭게 하셨으나, 그들이 그 은혜를 잊고 우상을 섬긴 것에 대해 심판을 선언하시면서도 여전히 아픈 사랑의 마음을 품고 계십니다.\n\n묵상 질문\n1. 내가 잊고 있는 하나님의 은혜는 무엇이며, 그것을 어떻게 기억할 수 있을까요?\n2. 하나님께서 주신 축복과 재능을 나는 무엇을 위해 사용하고 있나요?\n3. 하나님의 심판 속에서도 드러나는 그분의 사랑을 어떻게 이해할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-23', E'심판받는 이스라엘 (에스겔 17장)', E'에스겔 17장', E'에스겔 선지자는 하나님께서 주신 수수께끼와 비유를 통해 유다의 운명을 선포합니다. 두 마리의 독수리와 포도나무의 비유는 당시 국제 정세 속에서 유다가 처한 상황을 생생하게 보여줍니다. 첫 번째 독수리인 바벨론 왕 느부갓네살이 예루살렘에 와서 여호야긴 왕을 포로로 잡아가고, 그 대신 시드기야를 왕으로 세웠던 역사적 사실이 비유 속에 담겨 있습니다.\n\n하나님께서는 시드기야를 ''옥토에 심어진 포도나무''로 묘사하십니다. 바벨론의 보호 아래서 안전하게 자랄 수 있었던 포도나무였습니다. 그러나 이 포도나무는 첫 번째 독수리와의 언약을 저버리고 두 번째 독수리인 애굽을 향해 뿌리를 뻗고 가지를 돌렸습니다. 시드기야가 바벨론과의 언약을 배반하고 애굽에 군사적 도움을 요청한 것을 가리킵니다.\n\n하나님께서는 이 배신 행위를 단순한 정치적 실책으로 보지 않으셨습니다. "그가 내 맹세를 업신여기고 내 언약을 배반하였은즉"(겔 17:19)이라는 말씀은 시드기야가 바벨론과 맺은 언약이 하나님의 이름으로 맹세한 것임을 보여줍니다. 언약을 배반한 것은 곧 하나님을 배반한 것이었습니다. 그 결과 시드기야는 바벨론에서 비참한 최후를 맞이하게 될 것이라고 선포됩니다.\n\n그러나 하나님의 심판 선언은 절망으로 끝나지 않습니다. 하나님께서는 직접 백향목 꼭대기에서 연한 가지를 꺾어 이스라엘의 높은 산에 심으실 것을 약속하십니다. 이 새로운 나무는 무성하게 자라 모든 새들이 깃들이는 아름다운 백향목이 될 것입니다. 인간의 배신과 실패에도 불구하고 하나님께서는 당신의 백성을 위한 구원 계획을 포기하지 않으셨습니다. 메시아를 통한 새로운 희망의 약속이 어두운 심판의 메시지 가운데 빛나고 있습니다.', E'오늘의 핵심\n하나님께서는 언약을 배반한 시드기야의 운명을 통해 신실함의 중요성을 가르치시며, 동시에 직접 심으실 새로운 가지를 통해 구원의 소망을 약속하십니다.\n\n묵상 질문\n1. 내가 하나님과 사람 앞에서 맺은 약속들을 신실하게 지키고 있나요?\n2. 어려운 상황에서 하나님보다 세상의 힘을 의지하려는 유혹을 받은 적이 있나요?\n3. 실패와 심판 가운데서도 새로운 소망을 심으시는 하나님의 은혜를 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-24', E'심판받는 이스라엘 (에스겔 18장)', E'에스겔 18장', E'에스겔이 활동하던 시대에 예루살렘과 바빌론 포로 공동체 사이에는 한 가지 속담이 널리 퍼져 있었습니다. "아버지가 신 포도를 먹었으므로 그의 아들의 이가 시다"(겔 18:2)는 말이었습니다. 이 속담은 자신들이 겪는 고난의 책임을 조상들에게 돌리는 운명론적 사고를 담고 있었습니다. 포로로 끌려온 이들은 자신들의 처지를 한탄하며 하나님의 심판이 부당하다고 불평했습니다.\n\n하나님께서는 이러한 잘못된 생각을 단호하게 바로잡으십니다. 모든 영혼이 하나님께 속했으며, 각 사람은 자신의 행위에 따라 심판받는다는 원칙을 분명히 하십니다. 의로운 아버지라 할지라도 그 아들이 악을 행하면 아들은 죽을 것이며, 악한 아버지의 아들이라도 정의와 공의를 행하면 살 것이라고 말씀하십니다. \n\n특별히 주목할 것은 하나님께서 구체적으로 의인과 악인의 행위를 열거하신다는 점입니다. 산당에서 제물을 먹지 않고, 우상을 섬기지 않으며, 이웃의 아내를 범하지 않고, 가난한 자를 압제하지 않으며, 고리대금을 취하지 않는 것 - 이러한 실천적 의로움이 생명의 길이라고 가르치십니다.\n\n더욱 놀라운 것은 하나님의 은혜로운 선언입니다. 악인이라도 자신의 모든 죄에서 돌이켜 하나님의 율례를 지키면 반드시 살 것이며, 그의 지난 죄악은 기억되지 않을 것입니다. 하나님은 악인의 죽음을 기뻐하지 않으시고, 오히려 그가 돌이켜 사는 것을 기뻐하신다고 말씀하십니다. 이는 심판의 메시지 속에서도 회개와 회복의 길을 열어두시는 하나님의 자비하심을 보여줍니다.', E'오늘의 핵심\n하나님께서는 각 사람을 그 행위대로 심판하시되, 진심으로 회개하고 돌이키는 자에게는 새로운 생명의 기회를 주십니다.\n\n묵상 질문\n1. 내 삶의 어려움을 다른 사람이나 환경 탓으로 돌리고 있지는 않나요?\n2. 하나님께서 기뻐하시는 구체적인 의로움을 실천하고 있는지 점검해 보셨나요?\n3. 악인도 돌이키기를 원하시는 하나님의 마음이 내게 어떤 소망을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-25', E'심판받는 이스라엘 (에스겔 19장)', E'에스겔 19장', E'에스겔이 이스라엘 고관들을 위해 부르는 애가는 단순한 슬픔의 노래가 아니라, 하나님의 백성이 어떻게 몰락하게 되었는지를 보여주는 역사의 거울입니다. 이 애가는 두 개의 비유로 구성되어 있습니다. 첫 번째는 사자의 비유이고, 두 번째는 포도나무의 비유입니다.\n\n사자의 비유에서 암사자는 유다 왕국을, 그 새끼들은 유다의 왕들을 가리킵니다. 첫 번째 새끼는 요시야의 아들 여호아하스로, 그는 애굽으로 끌려갔습니다. 두 번째 새끼는 여호야김 또는 여호야긴으로 추정되며, 바벨론으로 잡혀갔습니다. 한때 용맹했던 젊은 사자들이 이방의 함정에 걸려 갈고리에 꿰이고 우리에 갇히는 모습은 유다 왕들의 비참한 운명을 생생하게 그려냅니다.\n\n포도나무의 비유는 유다 왕국의 과거 영광과 현재의 황폐함을 대비시킵니다. 물가에 심겨져 열매가 풍성하고 가지가 무성했던 포도나무는 한때 번영했던 다윗 왕조를 상징합니다. "권세 잡은 자의 규"가 될 만큼 강한 가지들은 왕권의 위엄을 나타냅니다. 그러나 이 영광스러운 포도나무는 "분노 중에 뽑혀서" 광야에 옮겨 심어지고, 동풍에 말라 불에 타버립니다. 더욱 비극적인 것은 불이 외부에서가 아니라 "그 가지 중 하나에서부터" 나와 스스로를 태웠다는 점입니다. 이는 유다의 멸망이 내부의 부패와 죄악으로부터 시작되었음을 암시합니다.\n\n에스겔의 애가는 단순히 과거를 슬퍼하는 것이 아니라, 하나님의 백성이 왜 심판을 받게 되었는지를 분명히 보여줍니다. 사자가 포획되고 포도나무가 불타는 것은 그들 자신의 죄악의 결과였습니다. 그러나 이 애가 속에서도 하나님의 주권적인 통치를 발견할 수 있습니다. 심판 가운데서도 하나님은 여전히 역사를 주관하고 계시며, 그분의 계획은 멈추지 않습니다.', E'오늘의 핵심\n에스겔의 애가는 유다 왕국의 몰락이 외부의 힘이 아닌 내부의 죄악과 부패로 인한 것임을 보여주며, 하나님의 공의로운 심판을 선포합니다.\n\n묵상 질문\n1. 내 삶의 영적 쇠퇴가 외부 환경 탓이 아닌 내적 문제에서 비롯된 것은 아닌지 돌아보셨나요?\n2. 하나님께서 주신 은혜와 권세를 어떻게 사용하고 있는지 점검해 보셨나요?\n3. 애가를 통해 회개로 나아가는 하나님의 마음을 느끼고 계신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-26', E'심판받는 이스라엘 (에스겔 20장)', E'에스겔 20장', E'이스라엘 장로들이 하나님께 묻기 위해 에스겔을 찾아왔지만, 하나님께서는 그들의 물음을 단호히 거절하십니다. "너희가 내게 묻기를 내가 용납하지 아니하리라"(겔 20:3)는 선언은 그들의 영적 상태가 얼마나 심각한지를 보여줍니다. 하나님께서는 에스겔을 통해 이스라엘의 과거 역사를 되돌아보게 하시는데, 그것은 애굽에서부터 시작된 반역의 역사였습니다.\n\n하나님께서는 이스라엘을 택하시고 애굽에서 구원하실 때부터 그들과 언약을 맺으셨습니다. 젖과 꿀이 흐르는 약속의 땅을 허락하시고, 생명을 얻게 하는 율례와 규례를 주셨으며, 안식일을 거룩하게 구별하여 하나님과 백성 사이의 표징으로 삼으셨습니다. 그러나 이스라엘은 애굽에서부터, 광야에서, 그리고 약속의 땅에 들어가서까지 계속해서 하나님께 반역했습니다. 그들은 우상을 버리지 않았고, 하나님의 율례를 멸시했으며, 안식일을 더럽혔습니다.\n\n특별히 주목할 점은 하나님께서 심판하지 않으신 이유입니다. 본문은 반복해서 "내가 내 이름을 위하여" 그들을 멸하지 않으셨다고 증언합니다. 이방 민족들 앞에서 하나님의 이름이 더럽혀지는 것을 원치 않으셨기 때문입니다. 이는 하나님의 신실하심과 인내하심을 보여주는 동시에, 이스라엘의 죄악이 얼마나 깊은지를 역설적으로 드러냅니다.\n\n그럼에도 불구하고 본문은 심판으로만 끝나지 않습니다. 하나님께서는 "능한 손과 편 팔로" 흩어진 백성을 다시 모으시고 다스리실 것을 선언하십니다. 이는 심판 가운데서도 여전히 역사하시는 하나님의 주권과, 끝까지 포기하지 않으시는 언약의 신실하심을 보여줍니다. 반역의 역사 속에서도 구원의 역사를 이루어가시는 하나님의 섭리가 여기 담겨 있습니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 반복된 반역의 역사를 돌아보게 하시면서도, 여전히 그들을 포기하지 않으시고 능하신 손으로 다스리실 것을 약속하십니다.\n\n묵상 질문\n1. 나의 신앙생활에도 반복되는 불순종의 패턴이 있지는 않나요?\n2. 하나님의 이름을 위해 참으시는 그분의 인내를 어떻게 받아들이고 있나요?\n3. 심판 중에도 포기하지 않으시는 하나님의 사랑을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-27', E'심판받는 이스라엘 (에스겔 21장)', E'에스겔 21장', E'여호와의 말씀이 에스겔에게 임하여 예루살렘을 향한 심판의 메시지를 전하게 하십니다. 하나님께서는 칼을 칼집에서 빼어 의인과 악인을 끊으시겠다고 선포하시는데, 이는 이스라엘이 끊임없이 하나님을 배역하고 우상을 숭배하며 불의를 행했기 때문입니다. 특히 "칼아 모이라 오른쪽을 치라 대열을 맞추라 왼쪽을 치라 향한 대로 가라"(겔 21:16)는 말씀은 하나님의 심판 도구인 바벨론이 얼마나 철저하게 예루살렘을 공격할 것인지를 보여줍니다.\n\n에스겔은 허리가 끊어지듯 탄식하라는 명령을 받습니다. 이는 단순한 슬픔의 표현이 아니라, 다가올 재앙의 참혹함을 백성들에게 미리 보여주는 예언적 행동이었습니다. 날카롭고 빛나는 칼의 이미지는 바벨론 군대의 무자비한 공격을 상징하며, 이스라엘의 왕과 고관들까지도 피할 수 없는 완전한 심판을 예고합니다.\n\n흥미로운 것은 바벨론 왕이 갈랫길에서 점을 쳐서 예루살렘으로 가는 길을 택하는 장면입니다. 인간의 눈에는 우연한 선택처럼 보이지만, 실상은 하나님께서 주권적으로 역사를 이끌어 가시는 모습을 보여줍니다. 바벨론 왕은 자신의 뜻대로 행한다고 생각하지만, 그 모든 과정이 하나님의 계획 안에서 이루어지고 있었던 것입니다.\n\n하나님은 높은 자를 낮추시고 낮은 자를 높이시는 분이십니다. 예루살렘의 왕관이 벗겨지고 영광이 사라지는 것은 그들이 하나님의 정의를 버리고 자신들의 욕심을 따랐기 때문입니다. 그러나 심판 가운데서도 소망의 빛이 비칩니다. "마땅히 얻을 자가 이르면 그에게 주리라"는 말씀은 장차 오실 메시아를 암시하며, 하나님의 구원 계획이 심판 너머에 있음을 보여줍니다.', E'오늘의 핵심\n하나님께서는 끝까지 회개하지 않는 예루살렘에 대해 바벨론을 통한 철저한 심판을 선포하시며, 이 모든 과정이 하나님의 주권적 통치 아래 있음을 보여주십니다.\n\n묵상 질문\n1. 하나님의 심판이 의인과 악인을 함께 끊는다는 말씀이 나에게 주는 경고는 무엇일까요?\n2. 오늘 내 삶에서 하나님의 주권적 인도하심을 어떻게 경험하고 있나요?\n3. 심판 중에도 구원의 소망을 품으신 하나님의 마음을 묵상할 때 어떤 감사가 생기나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-29', E'심판받는 이스라엘 (에스겔 22장)', E'에스겔 22장', E'하나님께서는 에스겔을 통해 예루살렘을 "피흘린 성읍"으로 부르시며 그들의 죄악을 낱낱이 드러내십니다. 한때 거룩한 도성이었던 예루살렘이 이제는 온갖 죄악으로 가득한 곳이 되어버렸습니다. 하나님께서 열거하시는 죄목들은 참으로 충격적입니다. 권력자들은 각기 권세를 이용해 피를 흘렸고, 백성들은 부모를 업신여기고 나그네와 고아와 과부를 학대했습니다. 거룩한 것을 업신여기고 안식일을 더럽혔으며, 온갖 성적 타락과 뇌물, 고리대금업으로 이웃을 착취했습니다.\n\n특별히 하나님의 마음을 아프게 한 것은 영적 지도자들의 타락이었습니다. 선지자들은 거짓을 전하며 백성의 영혼을 삼켰고, 제사장들은 하나님의 율법을 범하고 거룩한 것과 속된 것을 구별하지 않았습니다. 고관들은 불의한 이익을 위해 피를 흘렸습니다. 하나님께서는 이들을 풀무 속의 찌꺼기에 비유하시며, 정련의 불로 심판하실 것을 선포하십니다.\n\n가장 가슴 아픈 구절은 30절입니다. "이 땅을 위하여 성을 쌓으며 성 무너진 데를 막아 서서 나로 하여금 멸하지 못하게 할 사람을 내가 그 가운데에서 찾다가 찾지 못하였으므로." 하나님께서는 심판하기 원치 않으셨습니다. 단 한 사람이라도 중보자로 서서 기도하기를 바라셨지만, 그런 사람을 찾을 수 없었던 것입니다. 이것이 예루살렘 멸망의 결정적 이유였습니다. 죄악이 관영했을 뿐 아니라, 그 죄악의 틈새를 막아설 의인이 단 한 명도 없었던 것입니다.', E'오늘의 핵심\n하나님께서는 예루살렘의 총체적 타락상을 폭로하시며, 특히 영적 지도자들의 실패와 중보자의 부재가 심판을 피할 수 없게 만들었음을 보여주십니다.\n\n묵상 질문\n1. 오늘날 우리 사회와 교회 안에서 하나님께서 지적하실 만한 죄악은 무엇일까요?\n2. 하나님께서 나를 이 시대의 중보자로 부르신다면, 나는 어떻게 응답하겠습니까?\n3. 영적 지도자들의 타락이 공동체에 미치는 영향을 보며 무엇을 느끼십니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-30', E'이스라엘 주변 민족에 대한 심판 (에스겔 25장)', E'에스겔 25장', E'포로로 잡혀간 에스겔에게 하나님의 말씀이 임합니다. 이번에는 이스라엘 주변 나라들을 향한 심판의 메시지였습니다. 남유다가 바벨론의 침략을 받아 멸망의 위기에 처했을 때, 주변 나라들은 이를 기회로 여기며 조롱하고 약탈하려 했습니다. 그러나 하나님께서는 이들의 악행을 그냥 지나치지 않으셨습니다.\n\n먼저 암몬 족속에 대한 심판이 선포됩니다. 그들은 예루살렘 성전이 더럽혀지고 유다 백성이 포로로 잡혀갈 때 "아하 좋다"라고 조롱했습니다. 하나님의 백성이 고난당하는 것을 보며 기뻐한 그들에게, 하나님께서는 동방 민족들에게 정복당하여 노략을 당하게 될 것이라고 선언하십니다. 수도 랍바는 낙타의 우리가 되고, 그들의 땅은 양떼가 눕는 곳이 될 것입니다.\n\n모압과 세일도 심판을 피할 수 없었습니다. 그들은 "유다 족속은 모든 이방과 다름이 없다"고 말하며 하나님의 선택받은 백성을 무시했습니다. 이에 하나님께서는 모압의 국경 도시들을 열어 동방 사람들에게 넘겨주실 것을 선포하십니다.\n\n에돔은 형제 나라인 유다를 공격하여 원수를 갚았습니다. 야곱과 에서의 후손으로서 혈연관계였음에도 불구하고, 유다가 어려움에 처했을 때 도움은커녕 오히려 공격한 것입니다. 하나님께서는 데만에서 드단까지 에돔 전 지역을 황폐하게 하실 것을 선언하십니다.\n\n블레셋은 옛날부터 이스라엘을 미워하여 기회만 있으면 공격했습니다. 멸시하는 마음으로 원수를 갚고자 했던 그들에게도 하나님의 심판이 임할 것입니다. 그렛 사람들과 해변에 거주하는 자들이 진멸당할 것입니다.\n\n이 모든 심판 선언의 목적은 분명합니다. "내가 여호와인 줄을 너희가 알리라"는 말씀이 반복되는 것처럼, 하나님께서는 이스라엘뿐 아니라 모든 민족의 주권자이심을 나타내고자 하셨습니다. 남의 불행을 기뻐하고 약자를 괴롭히는 것은 결국 하나님의 공의로운 심판을 자초하는 일임을 보여주고 있습니다.', E'오늘의 핵심\n하나님께서는 자기 백성의 고난을 조롱하고 기뻐했던 주변 나라들에게 공의로운 심판을 선포하시며, 모든 민족의 주권자이심을 분명히 하십니다.\n\n묵상 질문\n1. 다른 사람의 어려움을 보며 은근히 기뻐했던 적은 없었나요?\n2. 하나님께서는 왜 이스라엘뿐 아니라 주변 나라들도 심판하실까요?\n3. "내가 여호와인 줄 알리라"는 말씀이 나에게 주는 의미는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-31', E'이스라엘 주변 민족에 대한 심판 (에스겔 26장)', E'에스겔 26장', E'다윗과 솔로몬 시대에 이스라엘과 우호적 관계를 유지하며 성전 건축에 큰 도움을 주었던 두로가 이제는 하나님의 심판 대상이 되었습니다. 지중해 연안의 항구도시 두로는 탁월한 해상무역으로 막대한 부를 축적했고, 그 부가 가져다준 힘과 영향력을 자랑하며 살았습니다. 그런데 무역 경쟁국이었던 예루살렘이 바벨론에게 함락되자, 두로는 이를 조롱하며 기뻐했습니다. "아하 만민의 문이 깨져서 내게로 돌아왔도다"(겔 26:2)라는 그들의 외침은 예루살렘의 멸망이 자신들에게 경제적 이익을 가져다줄 것이라는 계산에서 나온 것이었습니다.\n\n하나님께서는 두로의 이러한 태도에 대해 엄중한 심판을 선언하십니다. 바다가 파도를 굽이치게 하듯 여러 민족들이 두로를 치게 하실 것이며, 특별히 바벨론 왕 느부갓네살을 통해 그 심판을 이루실 것이라고 말씀하십니다. 한때 견고했던 성벽과 망대는 무너지고, 화려했던 도시는 맨 바위가 되어 그물을 말리는 곳으로 전락할 것입니다. 노래 소리와 수금 소리가 그치고, 다시는 재건되지 못할 것이라는 선언은 두로의 완전한 멸망을 예고합니다.\n\n이 예언의 말씀은 역사 속에서 그대로 성취되었습니다. 느부갓네살의 13년간의 포위 공격과 이후 알렉산더 대왕의 정복으로 두로는 철저히 파괴되었고, 한때 지중해의 여왕으로 불리던 그 영광은 사라졌습니다. 하나님께서는 이스라엘만의 하나님이 아니라 온 세계와 역사를 주관하시는 분이심을 두로의 심판을 통해 분명히 보여주고 계십니다. 남의 불행을 기뻐하고 자신의 부와 힘만을 의지했던 두로의 운명은, 하나님을 떠난 교만이 어떤 결과를 가져오는지를 엄중하게 경고합니다.', E'오늘의 핵심\n한때 이스라엘의 동맹국이었던 두로가 예루살렘의 멸망을 기뻐하며 경제적 이익을 계산했을 때, 하나님께서는 그들의 교만과 무정함에 대해 완전한 멸망으로 심판하십니다.\n\n묵상 질문\n1. 남의 어려움이 나에게 이익이 될 것이라고 계산하며 기뻐한 적은 없나요?\n2. 물질적 풍요와 성공이 가져다주는 교만의 위험을 어떻게 경계할 수 있을까요?\n3. 하나님께서 모든 나라와 민족의 역사를 주관하신다는 사실이 내게 주는 교훈은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-01', E'이스라엘 주변 민족에 대한 심판 (에스겔 27장)', E'에스겔 27장', E'지중해 연안의 부유한 항구 도시 두로를 향한 하나님의 심판이 선포됩니다. 에스겔은 두로를 화려한 무역선에 비유하여 그들의 영광과 몰락을 동시에 보여줍니다. 두로는 "나는 온전히 아름답다"(겔 27:3)라고 스스로를 자랑했습니다. 실제로 두로는 당대 최고의 무역 중심지였고, 지중해 전역과 거래하며 막대한 부를 축적했습니다. \n\n에스겔은 두로의 화려함을 배의 건조 과정과 운영으로 세밀하게 묘사합니다. 최고급 목재들로 선체와 돛대를 만들고, 이집트의 수놓은 베로 돛을 달았으며, 상아로 갑판을 장식했습니다. 시돈과 아르왓의 숙련된 사공들이 배를 운전하고, 각국의 용사들이 호위했습니다. 다시스에서 은과 철이, 야완에서 노예들이, 아라비아에서 가축들이, 스바에서 향료와 보석이 거래되었습니다. 이스라엘도 밀과 꿀과 기름으로 두로와 교역했습니다.\n\n그러나 하나님께서는 이 거대한 무역선이 동풍에 의해 바다 한가운데서 침몰할 것이라고 선포하십니다. 축적된 모든 재물과 상품, 선원들과 상인들이 함께 바다에 빠져 사라질 것입니다. 두로의 파멸을 목격한 주변 나라들은 충격에 빠지고, 그들과 거래하던 상인들은 비웃을 것입니다. \n\n두로의 심판은 단순히 한 도시의 멸망 이상의 의미를 담고 있습니다. 물질적 풍요와 경제력을 자랑하며 스스로를 높인 교만이 그들을 멸망으로 이끌었습니다. 하나님께서는 인간의 성취와 부가 아무리 대단해도 그분의 주권 앞에서는 한순간에 무너질 수 있음을 보여주십니다.', E'오늘의 핵심\n물질적 풍요를 의지하며 교만해진 두로는 하나님의 심판으로 바다 한가운데서 침몰하는 배처럼 완전히 파멸하게 됩니다.\n\n묵상 질문\n1. 내가 의지하는 것들이 한순간에 사라진다면 나는 어떤 존재로 남을까요?\n2. 경제적 성공이나 물질적 풍요가 나를 교만하게 만들고 있지는 않나요?\n3. 하나님의 주권을 인정하며 겸손히 살아가려면 어떤 결단이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-02', E'이스라엘 주변 민족에 대한 심판 (에스겔 28장)', E'에스겔 28장', E'에스겔 28장은 두로 왕의 교만과 멸망, 그리고 시돈에 대한 심판을 선포하며 하나님의 주권을 드러냅니다. 두로 왕은 자신의 지혜와 무역으로 축적한 부를 근거로 스스로를 신이라 칭하며 "나는 신이라 내가 하나님의 자리 곧 바다 가운데에 앉아 있다"(겔 28:2)고 선언합니다. 그의 지혜는 다니엘보다 뛰어나다고 자부했고, 무역을 통해 금과 은을 곳간에 쌓았습니다. 그러나 하나님께서는 그가 사람일 뿐 신이 아님을 분명히 하십니다.\n\n특별히 주목할 것은 두로 왕을 향한 슬픈 노래입니다. 하나님께서는 두로 왕이 한때 에덴동산에서 각종 보석으로 단장되고 기름 부음을 받은 그룹이었다고 묘사하십니다. 그는 하나님의 성산에서 불타는 돌들 사이를 왕래하며 창조된 날부터 완전했습니다. 그러나 무역이 번성하면서 그의 마음에 강포가 가득해졌고, 아름다움 때문에 교만해져서 지혜를 더럽혔습니다. 결국 하나님께서는 그를 성산에서 쫓아내시고 땅에 던져 재가 되게 하셨습니다.\n\n시돈에 대한 심판도 이어집니다. 하나님께서는 전염병과 칼로 시돈을 치실 것을 선포하십니다. 이 모든 심판을 통해 하나님께서는 당신의 거룩함을 나타내시고, 이스라엘을 멸시하던 가시 같은 존재들을 제거하실 것입니다. \n\n놀라운 것은 심판 선포 후에 주어지는 회복의 약속입니다. 흩어진 이스라엘 백성을 다시 모으시고, 야곱에게 주신 땅에서 평안히 거주하게 하실 것입니다. 그들은 집을 건축하고 포도원을 만들며 평화롭게 살 것입니다. 이는 교만한 자들은 멸망하지만, 하나님의 백성은 결국 회복된다는 소망의 메시지입니다.', E'오늘의 핵심\n하나님께서는 인간의 교만을 용납하지 않으시며, 스스로 신이 되려는 모든 시도를 심판하시지만, 동시에 당신의 백성을 위한 회복의 계획을 잊지 않으십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 자리를 차지하려는 교만한 마음은 없나요?\n2. 물질적 성공이 영적 타락으로 이어지지 않으려면 어떻게 해야 할까요?\n3. 하나님의 심판 가운데서도 회복의 소망을 품을 수 있는 이유는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-03', E'꺾이지 않는 신앙 (다니엘 3장)', E'다니엘 3장', E'바빌론 포로기는 이스라엘 백성에게 신앙의 시험대였습니다. 특히 우상숭배가 만연한 이방 땅에서 하나님을 향한 신실함을 지킨다는 것은 때로 생명을 걸어야 하는 일이었습니다. 느부갓네살 왕이 세운 거대한 금 신상은 바로 그런 시험의 현장이었습니다. 높이가 육십 규빗(약 27미터)에 달하는 이 금 신상은 왕의 권력과 바빌론의 영광을 상징하는 우상이었고, 모든 백성은 악기 소리가 들릴 때마다 이 신상 앞에 엎드려 절해야 했습니다.\n\n다니엘의 세 친구 사드락과 메삭과 아벳느고는 이 명령 앞에서 중대한 선택의 기로에 섰습니다. 그들은 이미 바빌론 사회에서 높은 지위에 올라 있었고, 왕의 신임을 받고 있었습니다. 그러나 그들에게는 타협할 수 없는 신앙의 원칙이 있었습니다. 조상들이 범했던 우상숭배의 죄를 되풀이할 수는 없었던 것입니다. \n\n왕 앞에 끌려온 세 사람의 대답은 놀라웠습니다. "왕이여 우리가 섬기는 하나님이 계시다면 우리를 맹렬히 타는 풀무불 가운데에서 능히 건져내시겠고 왕의 손에서도 건져내시리이다. 그렇게 하지 아니하실지라도 왕이여 우리가 왕의 신들을 섬기지도 아니하고 왕이 세우신 금 신상에게 절하지도 아니할 줄을 아옵소서"(단 3:17-18). 이들의 신앙고백은 하나님의 구원하심을 확신하면서도, 설령 구원받지 못한다 할지라도 우상에게 절하지 않겠다는 절대적 헌신을 보여줍니다.\n\n평소보다 일곱 배나 뜨겁게 달군 풀무불 속에서 하나님은 신실한 종들과 함께하셨습니다. 느부갓네살이 목격한 네 번째 인물은 하나님의 임재를 나타내는 것이었습니다. 불은 그들의 결박만을 태웠을 뿐, 머리털 하나 그을리지 못했습니다. 이 놀라운 구원의 역사는 교만한 왕으로 하여금 하나님을 찬송하게 만들었고, 세 사람은 더욱 높임을 받게 되었습니다. 하나님은 신앙을 지키는 자들을 결코 버리지 않으시며, 오히려 그들을 통해 당신의 영광을 드러내십니다.', E'오늘의 핵심\n사드락과 메삭과 아벳느고는 생명의 위협 앞에서도 하나님께 대한 절대적 신뢰와 헌신을 보여주었고, 하나님은 신실한 종들과 함께하시며 그들을 통해 영광을 받으셨습니다.\n\n묵상 질문\n1. 신앙을 지키기 위해 감수해야 할 대가가 클 때, 나는 어떤 선택을 하고 있나요?\n2. "그렇게 하지 아니하실지라도"라는 고백처럼, 상황과 관계없이 하나님을 신뢰할 수 있나요?\n3. 오늘 내가 직면한 신앙의 시험 앞에서 하나님의 임재를 어떻게 경험하고 있나요?');
